pub const MOVE_CATEGORY_SHEET: &str = "asset/pokemon_moba/icons/move_categories/move_categories";

#[derive(Clone, Copy, Debug)]
pub enum MoveCategory {
    Physical,
    Special,
    Status,
}

impl MoveCategory {
    pub const fn as_tag_part(self) -> &'static str {
        match self {
            Self::Physical => "physical",
            Self::Special => "special",
            Self::Status => "status",
        }
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum ActionSlot {
    Attack,
    Skill,
    Skill2,
    Ult,
}

impl ActionSlot {
    pub const fn action_name(self) -> &'static str {
        match self {
            Self::Attack => "attack",
            Self::Skill => "skill",
            Self::Skill2 => "skill2",
            Self::Ult => "ult",
        }
    }

    pub const fn index(self) -> usize {
        match self {
            Self::Attack => 0,
            Self::Skill => 1,
            Self::Skill2 => 2,
            Self::Ult => 3,
        }
    }
}

#[derive(Clone, Copy, Debug)]
pub struct PokemonMove {
    pub slot: ActionSlot,
    pub name_key: &'static str,
    pub move_type: PokemonType,
    pub category: MoveCategory,
    pub duration: usize,
    pub cooldown: usize,
    pub start_timing: usize,
    pub range: u64,
    pub growth_range: u64,
    pub casting: CastingType,
    pub target: CastingTarget,
    pub attack_type: AttackType,
    pub can_use_with_move: bool,
    pub effect: PokemonMoveEffect,
}

impl PokemonMove {
    pub fn icon_tag(self) -> String {
        format!(
            "{}_{}",
            self.move_type.asset_tag(),
            self.category.as_tag_part()
        )
    }
}

