#[derive(Clone, Copy, Debug)]
pub struct PokemonChampion {
    pub id: &'static str,
    pub display_name: &'static str,
    pub types: TypeSet,
    pub category: ChampionCategory,
    pub tags: &'static [ChampionTag],
    pub stat: EntityStat,
    pub growth: EntityStat,
    pub attack: PokemonMove,
    pub skill: PokemonMove,
    pub skill2: PokemonMove,
    pub ult: Option<PokemonMove>,
}

impl PokemonChampion {
    pub fn sprite_asset(self) -> String {
        format!("asset/pokemon_moba/champions/{}", self.short_id())
    }

    pub fn short_id(self) -> &'static str {
        self.id.strip_prefix("pokemon_moba_").unwrap_or(self.id)
    }
}

impl ModChampionInfo for PokemonChampion {
    fn id(&self) -> &str {
        self.id
    }

    fn name(&self) -> &str {
        self.display_name
    }

    fn skill_icon(&self, skill_index: usize) -> (String, String) {
        let action = match skill_index {
            0 => self.skill,
            1 => self.skill2,
            2 => self.ult.unwrap_or(self.skill2),
            _ => self.skill,
        };
        (MOVE_CATEGORY_SHEET.to_string(), action.icon_tag())
    }

    fn category(&self) -> ChampionCategory {
        self.category
    }

    fn tags(&self) -> Vec<ChampionTag> {
        self.tags.to_vec()
    }

    fn stat(&self) -> EntityStat {
        self.stat
    }

    fn growth(&self) -> EntityStat {
        self.growth
    }

    fn attack(&self) -> Box<dyn ModAction> {
        Box::new(PokemonAction::new(*self, self.attack))
    }

    fn skill(&self) -> Box<dyn ModAction> {
        Box::new(PokemonAction::new(*self, self.skill))
    }

    fn skill2(&self) -> Box<dyn ModAction> {
        Box::new(PokemonAction::new(*self, self.skill2))
    }

    fn ult(&self) -> Option<Box<dyn ModAction>> {
        self.ult
            .map(|action| Box::new(PokemonAction::new(*self, action)) as Box<dyn ModAction>)
    }

    fn passive(&self) -> Option<Box<dyn ModPassive>> {
        Some(Box::new(PokemonPassive::new(*self)))
    }
}

#[derive(Clone, Debug)]
struct PokemonAction {
    champion: PokemonChampion,
    action: PokemonMove,
}

impl PokemonAction {
    const fn new(champion: PokemonChampion, action: PokemonMove) -> Self {
        Self { champion, action }
    }

    fn engine_duration(&self) -> usize {
        self.action.duration.max(1)
    }

    fn engine_start_timing(&self) -> usize {
        self.action.start_timing.max(1).min(self.engine_duration())
    }

    fn engine_range(&self) -> u64 {
        self.action.range.max(1)
    }

    fn engine_growth_range(&self) -> u64 {
        self.action.growth_range.max(1)
    }
}

impl ModAction for PokemonAction {
    fn clone_box(&self) -> Box<dyn ModAction> {
        Box::new(self.clone())
    }

    fn action_name(&self) -> &str {
        self.action.slot.action_name()
    }

    fn duration(&self) -> usize {
        self.engine_duration()
    }

    fn cancelable(&self) -> bool {
        matches!(self.action.effect, PokemonMoveEffect::WishChannel { .. })
            || matches!(
                self.action.effect,
                PokemonMoveEffect::PowerUpPunchChannel { .. }
            )
            || matches!(self.action.slot, ActionSlot::Attack)
    }

    fn cooltime(&self, _caster_stat: &EntityStat, _caster_level: usize) -> usize {
        self.action.cooldown.max(1)
    }

    fn casting_target(&self) -> CastingTarget {
        self.action.target
    }

    fn effect(&self) -> Option<ModEffect> {
        Some(ModEffect {
            range: self.engine_range(),
            growth_range: self.engine_growth_range(),
            start_timing: self.engine_start_timing(),
            casting: self.action.casting,
            target: self.action.target,
            attack_type: self.action.attack_type,
            effect_type: Box::new(PokemonEffect {
                champion: self.champion,
                action: self.action,
            }),
        })
    }

    fn can_use_with_move(&self) -> bool {
        self.action.can_use_with_move
    }

    fn description(&self) -> String {
        action_description(self.champion, self.action)
    }
}

