    fn expected_total_damage(&self, caster_stat: &EntityStat) -> (usize, usize) {
        let (ad_damage, ap_damage) = self.base_damage(caster_stat);
        let hit_count = match self.action.effect {
            PokemonMoveEffect::MultiHitDamage { hits, .. } => hits,
            PokemonMoveEffect::CloysterIcicleCrash { hits_1, .. } => hits_1,
            PokemonMoveEffect::ChainDashDamage { max_targets, .. } => max_targets,
            _ => 1,
        };
        if let PokemonMoveEffect::IceField { duration_ticks, .. } = self.action.effect {
            let ticks = duration_ticks / Self::TICKS_PER_SECOND;
            return (
                ad_damage.saturating_mul(ticks),
                ap_damage.saturating_mul(ticks),
            );
        }
        if let PokemonMoveEffect::WhirlpoolField { duration_ticks, .. } = self.action.effect {
            let ticks = duration_ticks / 30;
            return (0, ap_damage.saturating_mul(ticks));
        }
        if let PokemonMoveEffect::BugBuzzAuraConfusion { duration_ticks, .. } = self.action.effect {
            let ticks = duration_ticks / 30;
            return (ad_damage.saturating_mul(ticks), 0);
        }
        if let PokemonMoveEffect::EarthquakeAura {
            duration_ticks,
            tick_interval,
            ..
        } = self.action.effect
        {
            let ticks = duration_ticks / tick_interval.max(1);
            return (ad_damage.saturating_mul(ticks), 0);
        }
        if let PokemonMoveEffect::SwannaFeatheryCyclone {
            duration_ticks,
            tick_interval,
            tick_base_ap,
            tick_ap_ratio,
            ..
        } = self.action.effect
        {
            let ticks = duration_ticks / tick_interval.max(1);
            return (
                0,
                (tick_base_ap + caster_stat.magic_power.saturating_mul(tick_ap_ratio) / 100)
                    .saturating_mul(ticks),
            );
        }
        if let PokemonMoveEffect::SwannaSkyCircus {
            hits,
            base_ap,
            ap_ratio,
            landing_base_ap,
            landing_ap_ratio,
            ..
        } = self.action.effect
        {
            return (
                0,
                (base_ap + caster_stat.magic_power.saturating_mul(ap_ratio) / 100)
                    .saturating_mul(hits)
                    .saturating_add(
                        landing_base_ap
                            + caster_stat.magic_power.saturating_mul(landing_ap_ratio) / 100,
                    ),
            );
        }
        if let PokemonMoveEffect::MarowakBonemerang {
            base_ad, ad_ratio, ..
        } = self.action.effect
        {
            let damage = base_ad + caster_stat.attack.saturating_mul(ad_ratio) / 100;
            return (damage.saturating_mul(2), 0);
        }
        if let PokemonMoveEffect::MarowakBoneRush {
            first_base_ad,
            first_ad_ratio,
            second_base_ad,
            second_ad_ratio,
            third_base_ad,
            third_ad_ratio,
            second_chance_percent,
            third_chance_percent,
            ..
        } = self.action.effect
        {
            let first = first_base_ad + caster_stat.attack.saturating_mul(first_ad_ratio) / 100;
            let second = second_base_ad + caster_stat.attack.saturating_mul(second_ad_ratio) / 100;
            let third = third_base_ad + caster_stat.attack.saturating_mul(third_ad_ratio) / 100;
            return (
                first
                    .saturating_add(second.saturating_mul(second_chance_percent) / 100)
                    .saturating_add(
                        third
                            .saturating_mul(second_chance_percent)
                            .saturating_mul(third_chance_percent)
                            / 10000,
                    ),
                0,
            );
        }
        if let PokemonMoveEffect::MarowakBoneWindmill {
            damage_base_ad,
            damage_ad_ratio,
            duration_ticks,
            tick_interval,
            ..
        } = self.action.effect
        {
            let tick_count = duration_ticks.saturating_div(tick_interval.max(1)).max(1);
            return (
                (damage_base_ad + caster_stat.attack.saturating_mul(damage_ad_ratio) / 100)
                    .saturating_mul(tick_count),
                0,
            );
        }
        (
            ad_damage.saturating_mul(hit_count),
            ap_damage
                .saturating_mul(hit_count)
                .saturating_add(self.expected_dot_damage(caster_stat)),
        )
    }

    fn expected_damage_for_ai(&self, caster_stat: &EntityStat) -> (usize, usize) {
        let damage = self.expected_total_damage(caster_stat);
        if damage != (0, 0) || matches!(self.action.effect, PokemonMoveEffect::None) {
            return damage;
        }

        match self.action.category {
            MoveCategory::Physical => (1, 0),
            MoveCategory::Special | MoveCategory::Status => (0, 1),
        }
    }

    fn burn_damage(&self, caster_stat: &EntityStat) -> usize {
        match self.action.effect {
            PokemonMoveEffect::ConeDamage {
                burn_base_ap,
                burn_ap_ratio,
                ..
            }
            | PokemonMoveEffect::DirectDamageChanceBurn {
                burn_base_ap,
                burn_ap_ratio,
                ..
            }
            | PokemonMoveEffect::DirectDamageChanceBurnBypassImmune {
                burn_base_ap,
                burn_ap_ratio,
                ..
            }
            | PokemonMoveEffect::SelfBuffAreaDamageKnockbackChanceBurn {
                burn_base_ap,
                burn_ap_ratio,
                ..
            }
            | PokemonMoveEffect::LinePierceDamageChanceBurn {
                burn_base_ap,
                burn_ap_ratio,
                ..
            }
            | PokemonMoveEffect::AreaDamageBurn {
                burn_base_ap,
                burn_ap_ratio,
                ..
            }
            | PokemonMoveEffect::DashDamageChanceBurn {
                burn_base_ap,
                burn_ap_ratio,
                ..
            }
            | PokemonMoveEffect::DirectBurn {
                burn_base_ap,
                burn_ap_ratio,
                ..
            }
            | PokemonMoveEffect::SelfAreaDamageBurn {
                burn_base_ap,
                burn_ap_ratio,
                ..
            }
            | PokemonMoveEffect::SelfAreaDamageBurnConfusion {
                burn_base_ap,
                burn_ap_ratio,
                ..
            }
            | PokemonMoveEffect::TravelingWaveDamageSlowBurn {
                burn_base_ap,
                burn_ap_ratio,
                ..
            }
            | PokemonMoveEffect::LineFirstDashDamageFlameTrail {
                trail_burn_base_ap: burn_base_ap,
                trail_burn_ap_ratio: burn_ap_ratio,
                ..
            }
            | PokemonMoveEffect::CoalossalMagmaStorm {
                burn_base_ap,
                burn_ap_ratio,
                ..
            } => burn_base_ap + caster_stat.magic_power.saturating_mul(burn_ap_ratio) / 100,
            PokemonMoveEffect::MagmortarHeatWave {
                burn_base_ad,
                burn_ad_ratio,
                ..
            }
            | PokemonMoveEffect::MagmortarEruption {
                burn_base_ad,
                burn_ad_ratio,
                ..
            } => burn_base_ad + caster_stat.attack.saturating_mul(burn_ad_ratio) / 100,
            _ => 0,
        }
    }

    fn bleed_damage(&self, caster_stat: &EntityStat) -> usize {
        match self.action.effect {
            PokemonMoveEffect::DirectDamageChanceBleed {
                bleed_base_ad,
                bleed_ad_ratio,
                ..
            }
            | PokemonMoveEffect::DirectDamageBleed {
                bleed_base_ad,
                bleed_ad_ratio,
                ..
            }
            | PokemonMoveEffect::DirectDamageEveryThirdBleed {
                bleed_base_ad,
                bleed_ad_ratio,
                ..
            } => bleed_base_ad + caster_stat.attack.saturating_mul(bleed_ad_ratio) / 100,
            _ => 0,
        }
    }

    fn expected_dot_damage(&self, caster_stat: &EntityStat) -> usize {
        match self.action.effect {
            PokemonMoveEffect::DirectDamageChanceBurn {
                burn_chance_percent,
                burn_ticks,
                ..
            }
            | PokemonMoveEffect::DirectDamageChanceBurnBypassImmune {
                burn_chance_percent,
                burn_ticks,
                ..
            }
            | PokemonMoveEffect::SelfBuffAreaDamageKnockbackChanceBurn {
                burn_chance_percent,
                burn_ticks,
                ..
            }
            | PokemonMoveEffect::LinePierceDamageChanceBurn {
                burn_chance_percent,
                burn_ticks,
                ..
            }
            | PokemonMoveEffect::DashDamageChanceBurn {
                burn_chance_percent,
                burn_ticks,
                ..
            }
            | PokemonMoveEffect::TravelingWaveDamageSlowBurn {
                burn_chance_percent,
                burn_ticks,
                ..
            }
            | PokemonMoveEffect::SelfAreaDamageBurnConfusion {
                burn_chance_percent,
                burn_ticks,
                ..
            }
            | PokemonMoveEffect::CoalossalMagmaStorm {
                burn_chance_percent,
                burn_ticks,
                ..
            } => {
                self.burn_damage(caster_stat)
                    .saturating_mul(burn_ticks / Self::TICKS_PER_SECOND)
                    .saturating_mul(burn_chance_percent)
                    / 100
            }
            PokemonMoveEffect::DirectBurn { burn_ticks, .. }
            | PokemonMoveEffect::SelfAreaDamageBurn { burn_ticks, .. }
            | PokemonMoveEffect::AreaDamageBurn { burn_ticks, .. } => self
                .burn_damage(caster_stat)
                .saturating_mul(burn_ticks / Self::TICKS_PER_SECOND),
            PokemonMoveEffect::DirectDamageChanceBleed {
                bleed_chance_percent,
                bleed_ticks,
                ..
            } => {
                self.bleed_damage(caster_stat)
                    .saturating_mul(bleed_ticks / Self::TICKS_PER_SECOND)
                    .saturating_mul(bleed_chance_percent)
                    / 100
            }
            PokemonMoveEffect::DirectDamageBleed { bleed_ticks, .. }
            | PokemonMoveEffect::DirectDamageEveryThirdBleed { bleed_ticks, .. } => self
                .bleed_damage(caster_stat)
                .saturating_mul(bleed_ticks / Self::TICKS_PER_SECOND),
            PokemonMoveEffect::LineFirstLeechSeed { duration_ticks, .. } => {
                let (_, damage_per_tick) = self.base_damage(caster_stat);
                damage_per_tick.saturating_mul(duration_ticks / Self::TICKS_PER_SECOND)
            }
            PokemonMoveEffect::LinePoisonSlow {
                poison_stacks,
                poison_damage,
                ..
            }
            | PokemonMoveEffect::TravelingWavePoisonSlow {
                poison_stacks,
                poison_damage,
                ..
            }
            | PokemonMoveEffect::TripleAreaDamagePoison {
                poison_stacks,
                poison_damage,
                ..
            } => poison_damage
                .saturating_mul(poison_stacks)
                .saturating_mul(15),
            PokemonMoveEffect::TravelingWaveDamageInfestation {
                infestation_ticks,
                infestation_base_ad,
                infestation_ad_ratio,
                ..
            } => {
                let damage_per_tick = infestation_base_ad
                    + caster_stat.attack.saturating_mul(infestation_ad_ratio) / 100;
                damage_per_tick.saturating_mul(infestation_ticks / 15)
            }
            PokemonMoveEffect::DirectDamageChancePoison {
                poison_chance_percent,
                poison_stacks,
                poison_damage,
                ..
            }
            | PokemonMoveEffect::SelfAreaDamageKnockbackChancePoison {
                poison_chance_percent,
                poison_stacks,
                poison_damage,
                ..
            } => {
                poison_damage
                    .saturating_mul(poison_stacks)
                    .saturating_mul(15)
                    .saturating_mul(poison_chance_percent)
                    / 100
            }
            PokemonMoveEffect::SelfAreaMiasmaDetonate {
                poison_stacks,
                poison_damage,
                ..
            } => poison_damage
                .saturating_mul(poison_stacks)
                .saturating_mul(15),
            PokemonMoveEffect::TargetPoison {
                stacks,
                poison_damage,
            }
            | PokemonMoveEffect::TargetPoisonExecute {
                stacks,
                poison_damage,
                ..
            } => poison_damage.saturating_mul(stacks).saturating_mul(15),
            PokemonMoveEffect::LineFirstDashDamageFlameTrail {
                trail_ticks,
                trail_base_ad,
                trail_ad_ratio,
                ..
            } => (trail_base_ad + caster_stat.attack.saturating_mul(trail_ad_ratio) / 100)
                .saturating_mul(trail_ticks / Self::TICKS_PER_SECOND),
            PokemonMoveEffect::LineFirstChargedDamage {
                base_ad,
                ad_ratio,
                charge_damage_percent,
                ..
            } => {
                let base = base_ad + caster_stat.attack.saturating_mul(ad_ratio) / 100;
                base.saturating_add(base.saturating_mul(charge_damage_percent) / 100)
            }
            PokemonMoveEffect::PowerUpPunchChannel {
                base_ad, ad_ratio, ..
            } => {
                let base = base_ad + caster_stat.attack.saturating_mul(ad_ratio) / 100;
                base.saturating_mul(21) / 10
            }
            _ => 0,
        }
    }

    fn expected_heal_amount(&self, caster_stat: &EntityStat) -> usize {
        match self.action.effect {
            PokemonMoveEffect::DirectDamageDrain { .. } => {
                let (ad_damage, ap_damage) = self.base_damage(caster_stat);
                ad_damage.saturating_add(ap_damage)
            }
            PokemonMoveEffect::LinePierceDamageDrain { .. } => {
                let (ad_damage, ap_damage) = self.base_damage(caster_stat);
                ad_damage.saturating_add(ap_damage)
            }
            PokemonMoveEffect::LineDashPierceContactDrain {
                pass_base_ap,
                pass_ap_ratio,
                lifesteal_percent,
                ..
            } => {
                let pass_damage =
                    pass_base_ap + caster_stat.magic_power.saturating_mul(pass_ap_ratio) / 100;
                pass_damage.saturating_mul(lifesteal_percent) / 100
            }
            PokemonMoveEffect::PollenPuff {
                base_heal,
                heal_ap_ratio,
                ..
            } => base_heal + caster_stat.magic_power.saturating_mul(heal_ap_ratio) / 100,
            PokemonMoveEffect::HealAttachedAllyPercent { hp_percent } => {
                caster_stat.hp.saturating_mul(hp_percent) / 100
            }
            PokemonMoveEffect::LineFirstLeechSeed { duration_ticks, .. } => {
                let (_, damage_per_tick) = self.base_damage(caster_stat);
                damage_per_tick.saturating_mul(duration_ticks / Self::TICKS_PER_SECOND)
            }
            PokemonMoveEffect::WishChannel {
                base_ap, ap_ratio, ..
            } => base_ap + caster_stat.magic_power.saturating_mul(ap_ratio) / 100,
            PokemonMoveEffect::AquaRing {
                duration_ticks,
                heal_base_ap,
                heal_ap_ratio,
                heal_defense_ratio,
                ..
            } => {
                let heal_per_tick = heal_base_ap
                    + caster_stat.magic_power.saturating_mul(heal_ap_ratio) / 100
                    + caster_stat.defence.saturating_mul(heal_defense_ratio) / 100;
                heal_per_tick.saturating_mul(duration_ticks / 30)
            }
            PokemonMoveEffect::WhirlpoolField {
                duration_ticks,
                self_heal_base_ap,
                self_heal_ap_ratio,
                ..
            } => {
                let heal_per_tick = self_heal_base_ap
                    + caster_stat.magic_power.saturating_mul(self_heal_ap_ratio) / 100;
                heal_per_tick.saturating_mul(duration_ticks / 30)
            }
            PokemonMoveEffect::MistyTerrain {
                duration_ticks,
                heal_per_tick,
                ..
            } => heal_per_tick.saturating_mul(duration_ticks / 30),
            PokemonMoveEffect::BlisseyHealAura {
                duration_ticks,
                heal_per_tick,
                ..
            } => heal_per_tick.saturating_mul(duration_ticks / 30),
            PokemonMoveEffect::CharmHeal {
                duration_ticks,
                heal_hp_ratio,
            } => {
                let heal_per_tick = caster_stat.hp.saturating_mul(heal_hp_ratio) / 100;
                heal_per_tick.saturating_mul(duration_ticks / Self::TICKS_PER_SECOND)
            }
            PokemonMoveEffect::Roost {
                duration_ticks,
                heal_per_tick,
            } => heal_per_tick.saturating_mul(duration_ticks / 30),
            PokemonMoveEffect::SelfSleepHeal {
                heal_ticks,
                heal_per_tick,
                ..
            } => heal_per_tick.saturating_mul(heal_ticks / Self::TICKS_PER_SECOND),
            PokemonMoveEffect::SelfHeal {
                base_heal,
                max_hp_ratio,
            }
            | PokemonMoveEffect::SelfHealResetPorygonType {
                base_heal,
                max_hp_ratio,
            } => base_heal + caster_stat.hp.saturating_mul(max_hp_ratio) / 100,
            PokemonMoveEffect::GlobalAllyHealPercent { hp_percent } => {
                caster_stat.hp.saturating_mul(hp_percent) / 100
            }
            _ => 0,
        }
    }

