fn targets_for_effect(
    ctx: &GameCtx,
    effect: PokemonMoveEffect,
    caster_id: usize,
    caster_team: usize,
    caster_pos: EntityPos,
    input: InputTarget,
) -> Vec<usize> {
    match effect {
        PokemonMoveEffect::LineDamageAndParalysis { width, .. } => {
            let Some(target_pos) = input_position(ctx, input) else {
                return Vec::new();
            };
            collect_enemy_targets(ctx, caster_team, |pos| {
                distance_to_segment_sq(pos, caster_pos, target_pos) <= width.saturating_mul(width)
            })
        }
        PokemonMoveEffect::TravelingWaveDamage {
            travel_range,
            wall_length,
            ..
        }
        | PokemonMoveEffect::TravelingWaveDamageInfestation {
            travel_range,
            wall_length,
            ..
        }
        | PokemonMoveEffect::TravelingWaveDamageSlowBurn {
            travel_range,
            wall_length,
            ..
        }
        | PokemonMoveEffect::TravelingWaveDamageParalysis {
            travel_range,
            wall_length,
            ..
        }
        | PokemonMoveEffect::TravelingWaveDamageChanceFreeze {
            travel_range,
            wall_length,
            ..
        }
        | PokemonMoveEffect::WishiwashiWaveSplash {
            travel_range,
            wall_length,
            ..
        }
        | PokemonMoveEffect::TravelingWaveDamageTerrify {
            travel_range,
            wall_length,
            ..
        } => {
            let Some(end_pos) = traveling_wave_end(ctx, input, caster_pos, travel_range) else {
                return Vec::new();
            };
            let half_wall = wall_length / 2;
            collect_enemy_targets(ctx, caster_team, |pos| {
                distance_to_segment_sq(pos, caster_pos, end_pos)
                    <= half_wall.saturating_mul(half_wall)
            })
        }
        PokemonMoveEffect::LineDashPierceDamage { width, .. }
        | PokemonMoveEffect::LineDashPierceContactDrain { width, .. } => {
            let Some(target_pos) = input_position(ctx, input) else {
                return Vec::new();
            };
            collect_enemy_targets(ctx, caster_team, |pos| {
                distance_to_segment_sq(pos, caster_pos, target_pos) <= width.saturating_mul(width)
            })
        }
        PokemonMoveEffect::StarmiePsybeam {
            width,
            travel_range,
            ..
        } => {
            let Some(end_pos) = traveling_wave_end(ctx, input, caster_pos, travel_range) else {
                return Vec::new();
            };
            collect_enemy_targets(ctx, caster_team, |pos| {
                distance_to_segment_sq(pos, caster_pos, end_pos) <= width.saturating_mul(width)
            })
        }
        PokemonMoveEffect::DedennePlayRough {
            width,
            normal_range,
            ..
        } => {
            let Some(end_pos) = traveling_wave_end(ctx, input, caster_pos, normal_range) else {
                return Vec::new();
            };
            collect_enemy_targets(ctx, caster_team, |pos| {
                distance_to_segment_sq(pos, caster_pos, end_pos) <= width.saturating_mul(width)
            })
        }
        PokemonMoveEffect::AreaDamage { radius, .. }
        | PokemonMoveEffect::AreaDamageBurn { radius, .. }
        | PokemonMoveEffect::AreaDamageSelfSlow { radius, .. }
        | PokemonMoveEffect::IceField { radius, .. }
        | PokemonMoveEffect::WhirlpoolField { radius, .. }
        | PokemonMoveEffect::AreaMiasmaSlow { radius, .. }
        | PokemonMoveEffect::ShiftryTornado { radius, .. }
        | PokemonMoveEffect::SwannaSkyCircus { radius, .. }
        | PokemonMoveEffect::AreaSoak { radius, .. } => {
            let Some(target_pos) = input_position(ctx, input) else {
                return Vec::new();
            };
            collect_enemy_targets(ctx, caster_team, |pos| {
                distance_sq(pos, target_pos) <= radius.saturating_mul(radius)
            })
        }
        PokemonMoveEffect::TripleAreaDamage { radius, spread, .. }
        | PokemonMoveEffect::TripleAreaDamagePoison { radius, spread, .. } => {
            let Some(target_pos) = input_position(ctx, input) else {
                return Vec::new();
            };
            let centers = triangle_area_centers(caster_pos, target_pos, spread);
            collect_enemy_targets(ctx, caster_team, |pos| {
                centers
                    .iter()
                    .any(|center| distance_sq(pos, *center) <= radius.saturating_mul(radius))
            })
        }
        PokemonMoveEffect::ShellTrap {
            trap_radius,
            spread,
            ..
        } => {
            let Some(target_pos) = input_position(ctx, input) else {
                return Vec::new();
            };
            let centers = triangle_area_centers(caster_pos, target_pos, spread);
            collect_enemy_targets(ctx, caster_team, |pos| {
                centers.iter().any(|center| {
                    distance_sq(pos, *center) <= trap_radius.saturating_mul(trap_radius)
                })
            })
        }
        PokemonMoveEffect::SunnyDay { length, width, .. }
        | PokemonMoveEffect::RainDance { length, width, .. } => {
            let Some(target_pos) = input_position(ctx, input) else {
                return Vec::new();
            };
            collect_enemy_targets(ctx, caster_team, |pos| {
                is_inside_cast_rectangle(pos, caster_pos, target_pos, length, width)
            })
        }
        PokemonMoveEffect::DragonCheerAura { .. } | PokemonMoveEffect::LifeDewPickups { .. } => {
            Vec::new()
        }
        PokemonMoveEffect::BouncingAreaDamage {
            radius,
            bounce_distance,
            ..
        } => {
            let Some(target_pos) = input_position(ctx, input) else {
                return Vec::new();
            };
            let centers = bouncing_area_centers(caster_pos, target_pos, bounce_distance);
            collect_enemy_targets(ctx, caster_team, |pos| {
                centers
                    .iter()
                    .any(|center| distance_sq(pos, *center) <= radius.saturating_mul(radius))
            })
        }
        PokemonMoveEffect::AreaDamageDefenseDebuff { radius, .. }
        | PokemonMoveEffect::AreaDamageAttackDebuff { radius, .. }
        | PokemonMoveEffect::AreaAttackDefenseDebuff { radius, .. }
        | PokemonMoveEffect::SelfAreaDamage { radius, .. }
        | PokemonMoveEffect::SelfAreaDamageFreezeAll { radius, .. }
        | PokemonMoveEffect::SelfAreaMiasmaDetonate { radius, .. }
        | PokemonMoveEffect::SelfAreaDamageThrow { radius, .. }
        | PokemonMoveEffect::DedenneParabolicDischarge { radius, .. }
        | PokemonMoveEffect::DazzlingGleam { radius, .. } => {
            collect_enemy_targets(ctx, caster_team, |pos| {
                distance_sq(pos, caster_pos) <= radius.saturating_mul(radius)
            })
        }
        PokemonMoveEffect::SelfAreaDamageRetreatLine {
            radius,
            width,
            dash_range,
            ..
        } => {
            let retreat_end = input_position(ctx, input)
                .map(|target_pos| retreat_line_end(caster_pos, target_pos, dash_range));
            collect_enemy_targets(ctx, caster_team, |pos| {
                distance_sq(pos, caster_pos) <= radius.saturating_mul(radius)
                    || retreat_end
                        .map(|end_pos| {
                            distance_to_segment_sq(pos, caster_pos, end_pos)
                                <= width.saturating_mul(width)
                        })
                        .unwrap_or(false)
            })
        }
        PokemonMoveEffect::EarthquakeAura { .. } => Vec::new(),
        PokemonMoveEffect::TrailblazeGrassyTerrain { search_radius, .. } => {
            crate::pokemon_status::grassy_terrain_trailblaze_targets(ctx, caster_id, search_radius)
        }
        PokemonMoveEffect::ConeDamage {
            length,
            width_at_end,
            ..
        } => {
            let Some(target_pos) = input_position(ctx, input) else {
                return Vec::new();
            };
            collect_enemy_targets(ctx, caster_team, |pos| {
                is_inside_cone(pos, caster_pos, target_pos, length, width_at_end)
            })
        }
        PokemonMoveEffect::ConeDamageFreeze {
            length,
            width_at_end,
            ..
        }
        | PokemonMoveEffect::ConeDamageBlind {
            length,
            width_at_end,
            ..
        }
        | PokemonMoveEffect::ConeDamageConfusion {
            length,
            width_at_end,
            ..
        }
        | PokemonMoveEffect::ConeTauntThenConfuse {
            length,
            width_at_end,
            ..
        }
        | PokemonMoveEffect::ConeForceAwaySlow {
            length,
            width_at_end,
            ..
        } => {
            let Some(target_pos) = input_position(ctx, input) else {
                return Vec::new();
            };
            collect_enemy_targets(ctx, caster_team, |pos| {
                is_inside_cone(pos, caster_pos, target_pos, length, width_at_end)
            })
        }
        PokemonMoveEffect::MeleeArcDamage {
            arc_range,
            arc_width,
            ..
        } => {
            let Some(target_pos) = input_position(ctx, input) else {
                return Vec::new();
            };
            collect_enemy_targets(ctx, caster_team, |pos| {
                is_inside_melee_arc(pos, caster_pos, target_pos, arc_range, arc_width)
            })
        }
        PokemonMoveEffect::DashEndConeDamage {
            dash_range,
            cone_length,
            cone_width,
            ..
        } => {
            let Some(end_pos) = traveling_wave_end(ctx, input, caster_pos, dash_range) else {
                return Vec::new();
            };
            let Some(target_pos) = input_position(ctx, input) else {
                return Vec::new();
            };
            collect_enemy_targets(ctx, caster_team, |pos| {
                is_inside_cone(pos, end_pos, target_pos, cone_length, cone_width)
            })
        }
        PokemonMoveEffect::ChainDashDamage {
            chain_radius,
            max_targets,
            ..
        } => chain_dash_targets(ctx, caster_team, input, chain_radius, max_targets),
        PokemonMoveEffect::LineFirstDamage { width, .. }
        | PokemonMoveEffect::LineFirstDamageSelfBuff { width, .. }
        | PokemonMoveEffect::LineFirstDashDamageFlameTrail { width, .. }
        | PokemonMoveEffect::LineFirstDashDamageMissingHp { width, .. }
        | PokemonMoveEffect::LineFirstDashDamageDistanceSelfHp { width, .. }
        | PokemonMoveEffect::LineFirstChargedDamage { width, .. }
        | PokemonMoveEffect::QuaquavalSpiralShot { width, .. } => {
            let Some(target_pos) = input_position(ctx, input) else {
                return Vec::new();
            };
            first_enemy_on_line(ctx, caster_team, caster_pos, target_pos, width)
                .into_iter()
                .collect()
        }
        PokemonMoveEffect::LinePierceDamage { width, .. }
        | PokemonMoveEffect::LinePierceDamageDrain { width, .. }
        | PokemonMoveEffect::LinePierceDamageStun { width, .. }
        | PokemonMoveEffect::LineExecute { width, .. }
        | PokemonMoveEffect::TriAttack { width, .. }
        | PokemonMoveEffect::LinePierceDamageChanceBurn { width, .. }
        | PokemonMoveEffect::LinePierceDamageSelfDefenseDebuff { width, .. }
        | PokemonMoveEffect::LinePierceDamageChanceFreeze { width, .. }
        | PokemonMoveEffect::LinePierceDamageSlowApToAd { width, .. }
        | PokemonMoveEffect::LinePierceDamageMiasmaCoil { width, .. }
        | PokemonMoveEffect::LinePierceDamageSelfRetreat { width, .. }
        | PokemonMoveEffect::YanmegaBuzzingBoost { width, .. } => {
            let Some(target_pos) = input_position(ctx, input) else {
                return Vec::new();
            };
            collect_enemy_targets(ctx, caster_team, |pos| {
                distance_to_segment_sq(pos, caster_pos, target_pos) <= width.saturating_mul(width)
            })
        }
        PokemonMoveEffect::TripleArcDamage { width, spread, .. } => {
            let Some(target_pos) = input_position(ctx, input) else {
                return Vec::new();
            };
            triple_arc_targets(ctx, caster_team, caster_pos, target_pos, width, spread)
        }
        PokemonMoveEffect::SelfBuffAreaDamage { radius, .. }
        | PokemonMoveEffect::SelfBuffAreaDamageKnockbackChanceBurn { radius, .. }
        | PokemonMoveEffect::SelfAreaDamageBurn { radius, .. }
        | PokemonMoveEffect::SelfAreaDamageBurnConfusion { radius, .. }
        | PokemonMoveEffect::SelfAreaDamageKnockbackChancePoison { radius, .. }
        | PokemonMoveEffect::SelfAreaDamageParalysis { radius, .. }
        | PokemonMoveEffect::ShedTailTauntDash { radius, .. } => {
            collect_enemy_targets(ctx, caster_team, |pos| {
                distance_sq(pos, caster_pos) <= radius.saturating_mul(radius)
            })
        }
        PokemonMoveEffect::LineFirstLeechSeed { width, .. } => {
            let Some(target_pos) = input_position(ctx, input) else {
                return Vec::new();
            };
            first_enemy_on_line(ctx, caster_team, caster_pos, target_pos, width)
                .into_iter()
                .collect()
        }
        PokemonMoveEffect::LineFirstBindBoth { width, .. } => {
            let Some(target_pos) = input_position(ctx, input) else {
                return Vec::new();
            };
            first_enemy_on_line(ctx, caster_team, caster_pos, target_pos, width)
                .into_iter()
                .collect()
        }
        PokemonMoveEffect::LinePoisonSlow { width, .. } => {
            let Some(target_pos) = input_position(ctx, input) else {
                return Vec::new();
            };
            collect_enemy_targets(ctx, caster_team, |pos| {
                distance_to_segment_sq(pos, caster_pos, target_pos) <= width.saturating_mul(width)
            })
        }
        PokemonMoveEffect::TravelingWavePoisonSlow {
            travel_range,
            wall_length,
            ..
        } => {
            let Some(end_pos) = traveling_wave_end(ctx, input, caster_pos, travel_range) else {
                return Vec::new();
            };
            let half_wall = wall_length / 2;
            collect_enemy_targets(ctx, caster_team, |pos| {
                distance_to_segment_sq(pos, caster_pos, end_pos)
                    <= half_wall.saturating_mul(half_wall)
            })
        }
        PokemonMoveEffect::WishChannel { .. }
        | PokemonMoveEffect::Sketch
        | PokemonMoveEffect::PollenPuff { .. }
        | PokemonMoveEffect::CharmHeal { .. }
        | PokemonMoveEffect::BatonPass { .. }
        | PokemonMoveEffect::Instruct { .. }
        | PokemonMoveEffect::AllyDamageRedirect { .. }
        | PokemonMoveEffect::AllySwapHeal { .. }
        | PokemonMoveEffect::RescueAllyDash { .. }
        | PokemonMoveEffect::EndureBuff { .. }
        | PokemonMoveEffect::TargetPoisonExecute { .. } => match input {
            InputTarget::Target { target_id } => vec![target_id],
            _ => Vec::new(),
        },
        PokemonMoveEffect::AquaRing { .. }
        | PokemonMoveEffect::MistyTerrain { .. }
        | PokemonMoveEffect::LightScreen { .. }
        | PokemonMoveEffect::SmokeScreen { .. }
        | PokemonMoveEffect::SwannaFeatheryCyclone { .. }
        | PokemonMoveEffect::MagmortarHeatWave { .. }
        | PokemonMoveEffect::CoalossalMagmaStorm { .. }
        | PokemonMoveEffect::ArcanineExtremespeed { .. }
        | PokemonMoveEffect::ArcanineWhiteFlames { .. }
        | PokemonMoveEffect::MarowakBonemerang { .. }
        | PokemonMoveEffect::MarowakBoneRush { .. }
        | PokemonMoveEffect::MarowakBoneWindmill { .. } => Vec::new(),
        PokemonMoveEffect::DedenneElectricTerrain { .. } => Vec::new(),
        PokemonMoveEffect::BrineField { .. }
        | PokemonMoveEffect::StickyWebField { .. }
        | PokemonMoveEffect::SingAura { .. }
        | PokemonMoveEffect::SleepPowderCircle { .. }
        | PokemonMoveEffect::BugBuzzAuraConfusion { .. }
        | PokemonMoveEffect::AlluringVoiceAura { .. }
        | PokemonMoveEffect::BlisseyHealAura { .. }
        | PokemonMoveEffect::SelfCleanseOffenseBuff { .. }
        | PokemonMoveEffect::SelfAttackDefenseBuff { .. }
        | PokemonMoveEffect::SelfAttackDualDefenseBuff { .. }
        | PokemonMoveEffect::QuaquavalExcitingDance { .. }
        | PokemonMoveEffect::ArcanineFlamesOfRage { .. }
        | PokemonMoveEffect::ReversalGuard { .. }
        | PokemonMoveEffect::StoredPower { .. }
        | PokemonMoveEffect::GlobalAllyHealPercent { .. } => Vec::new(),
        PokemonMoveEffect::PowerUpPunchChannel { .. } => Vec::new(),
        _ => match input {
            InputTarget::Target { target_id }
                if !crate::pokemon_status::is_soft_untargetable(ctx, target_id) =>
            {
                vec![target_id]
            }
            _ => Vec::new(),
        },
    }
}

fn target_is_tower(ctx: &GameCtx, target_id: usize) -> bool {
    ctx.get_entity(target_id)
        .map(|target| target.is_tower())
        .unwrap_or(false)
}

fn move_allows_tower_damage(champion: PokemonChampion, action: PokemonMove) -> bool {
    if matches!(action.slot, ActionSlot::Attack) {
        return true;
    }

    matches!(
        (champion.id, action.slot),
        ("pokemon_moba_hitmonlee", ActionSlot::Skill2)
            | ("pokemon_moba_clawitzer", ActionSlot::Skill2)
            | ("pokemon_moba_clawitzer", ActionSlot::Ult)
            | ("pokemon_moba_gallade", ActionSlot::Ult)
    )
}

fn move_damage_target_allowed(
    ctx: &GameCtx,
    champion: PokemonChampion,
    action: PokemonMove,
    target_id: usize,
) -> bool {
    !target_is_tower(ctx, target_id) || move_allows_tower_damage(champion, action)
}

fn filter_move_damage_targets(
    ctx: &GameCtx,
    champion: PokemonChampion,
    action: PokemonMove,
    targets: Vec<usize>,
) -> Vec<usize> {
    targets
        .into_iter()
        .filter(|target_id| move_damage_target_allowed(ctx, champion, action, *target_id))
        .collect()
}

