fn fire_web_burn_area(
    ctx: &GameCtx,
    effect: PokemonMoveEffect,
    caster_pos: EntityPos,
    input: InputTarget,
) -> Option<(EntityPos, u64)> {
    match effect {
        PokemonMoveEffect::AreaDamage { radius, .. }
        | PokemonMoveEffect::AreaDamageBurn { radius, .. }
        | PokemonMoveEffect::AreaDamageSelfSlow { radius, .. }
        | PokemonMoveEffect::TripleAreaDamage { radius, .. } => {
            input_position(ctx, input).map(|center| (center, radius))
        }
        PokemonMoveEffect::SelfAreaDamageBurn { radius, .. }
        | PokemonMoveEffect::SelfAreaDamageBurnConfusion { radius, .. }
        | PokemonMoveEffect::SelfBuffAreaDamageKnockbackChanceBurn { radius, .. }
        | PokemonMoveEffect::SelfBuffAreaDamage { radius, .. } => Some((caster_pos, radius)),
        _ => None,
    }
}

fn draw_impact_circle(ctx: &mut GameCtx, pos: EntityPos, radius: u64, color: u32) {
    ctx.debug_draw_circle(pos.x, pos.y, radius, color);
    ctx.debug_draw_circle(pos.x, pos.y, radius.saturating_mul(2) / 3, color);
    ctx.debug_draw_line(
        pos.x.saturating_sub(radius),
        pos.y,
        pos.x.saturating_add(radius),
        pos.y,
        color,
    );
    ctx.debug_draw_line(
        pos.x,
        pos.y.saturating_sub(radius),
        pos.x,
        pos.y.saturating_add(radius),
        color,
    );
}

fn draw_chain_visual(ctx: &mut GameCtx, from: EntityPos, to: EntityPos, color: u32) {
    draw_line_band(ctx, from, to, 4500, color);
    for index in 1..6 {
        let x = interpolate_u64(from.x, to.x, index, 6);
        let y = interpolate_u64(from.y, to.y, index, 6);
        draw_impact_circle(ctx, EntityPos { x, y }, 5500, color);
    }
    draw_impact_circle(ctx, to, 11000, color);
}

fn draw_cast_rectangle(
    ctx: &mut GameCtx,
    start: EntityPos,
    target: EntityPos,
    length: u64,
    width: u64,
    color: u32,
) {
    let dx = target.x as f64 - start.x as f64;
    let dy = target.y as f64 - start.y as f64;
    let len = (dx * dx + dy * dy).sqrt();
    if len <= 0.0 {
        return;
    }
    let end = pos_from_f64(
        start.x as f64 + dx / len * length as f64,
        start.y as f64 + dy / len * length as f64,
    );
    draw_line_band(ctx, start, end, width / 2, color);
    ctx.debug_draw_line(start.x, start.y, end.x, end.y, color);
}

fn interpolate_u64(start: u64, end: u64, step: usize, steps: usize) -> u64 {
    let start = start as i128;
    let end = end as i128;
    let step = step as i128;
    let steps = steps.max(1) as i128;
    (start + (end - start) * step / steps).clamp(0, u64::MAX as i128) as u64
}

fn draw_field_circle(ctx: &mut GameCtx, pos: EntityPos, radius: u64, color: u32) {
    ctx.debug_draw_circle(pos.x, pos.y, radius, color);
    ctx.debug_draw_circle(pos.x, pos.y, radius.saturating_mul(3) / 4, color);
    ctx.debug_draw_circle(pos.x, pos.y, radius / 2, color);
}

fn draw_self_buff_visual(ctx: &mut GameCtx, pos: EntityPos, radius: u64, color: u32) {
    draw_field_circle(ctx, pos, radius, color);
    ctx.debug_draw_line(
        pos.x.saturating_sub(radius / 2),
        pos.y.saturating_add(radius / 2),
        pos.x.saturating_add(radius / 2),
        pos.y.saturating_sub(radius / 2),
        color,
    );
    ctx.debug_draw_line(
        pos.x.saturating_sub(radius / 2),
        pos.y.saturating_sub(radius / 2),
        pos.x.saturating_add(radius / 2),
        pos.y.saturating_add(radius / 2),
        color,
    );
}

fn draw_line_band(ctx: &mut GameCtx, start: EntityPos, end: EntityPos, width: u64, color: u32) {
    ctx.debug_draw_line(start.x, start.y, end.x, end.y, color);
    let dx = end.x as f64 - start.x as f64;
    let dy = end.y as f64 - start.y as f64;
    let len = (dx * dx + dy * dy).sqrt();
    if len <= 0.0 {
        return;
    }

    let perp_x = -dy / len;
    let perp_y = dx / len;
    let offset = width as f64;
    let s1 = pos_from_f64(
        start.x as f64 + perp_x * offset,
        start.y as f64 + perp_y * offset,
    );
    let e1 = pos_from_f64(
        end.x as f64 + perp_x * offset,
        end.y as f64 + perp_y * offset,
    );
    let s2 = pos_from_f64(
        start.x as f64 - perp_x * offset,
        start.y as f64 - perp_y * offset,
    );
    let e2 = pos_from_f64(
        end.x as f64 - perp_x * offset,
        end.y as f64 - perp_y * offset,
    );
    ctx.debug_draw_line(s1.x, s1.y, e1.x, e1.y, color);
    ctx.debug_draw_line(s2.x, s2.y, e2.x, e2.y, color);
    ctx.debug_draw_circle(start.x, start.y, width / 2, color);
    ctx.debug_draw_circle(end.x, end.y, width / 2, color);
}

fn draw_traveling_wave(
    ctx: &mut GameCtx,
    start: EntityPos,
    end: EntityPos,
    wall_length: u64,
    thickness: u64,
    color: u32,
) {
    let half_wall = wall_length / 2;
    draw_line_band(ctx, start, end, half_wall, color);

    let mid = pos_from_f64(
        (start.x as f64 + end.x as f64) / 2.0,
        (start.y as f64 + end.y as f64) / 2.0,
    );
    for center in [start, mid, end] {
        let (left, right) = perpendicular_segment_at(start, end, center, wall_length);
        ctx.debug_draw_line(left.x, left.y, right.x, right.y, color);
        ctx.debug_draw_circle(center.x, center.y, thickness.max(4000), color);
    }
}

fn perpendicular_segment_at(
    start: EntityPos,
    end: EntityPos,
    center: EntityPos,
    length: u64,
) -> (EntityPos, EntityPos) {
    let dx = end.x as f64 - start.x as f64;
    let dy = end.y as f64 - start.y as f64;
    let len = (dx * dx + dy * dy).sqrt();
    if len <= 0.0 {
        return (center, center);
    }

    let perp_x = -dy / len;
    let perp_y = dx / len;
    let half = length as f64 / 2.0;
    (
        pos_from_f64(
            center.x as f64 + perp_x * half,
            center.y as f64 + perp_y * half,
        ),
        pos_from_f64(
            center.x as f64 - perp_x * half,
            center.y as f64 - perp_y * half,
        ),
    )
}

fn parallel_line_segments(
    start: EntityPos,
    end: EntityPos,
    offset: u64,
) -> (EntityPos, EntityPos, EntityPos, EntityPos) {
    let dx = end.x as f64 - start.x as f64;
    let dy = end.y as f64 - start.y as f64;
    let len = (dx * dx + dy * dy).sqrt();
    if len <= 0.0 {
        return (start, end, start, end);
    }

    let perp_x = -dy / len;
    let perp_y = dx / len;
    let offset = offset as f64;
    (
        pos_from_f64(
            start.x as f64 + perp_x * offset,
            start.y as f64 + perp_y * offset,
        ),
        pos_from_f64(
            end.x as f64 + perp_x * offset,
            end.y as f64 + perp_y * offset,
        ),
        pos_from_f64(
            start.x as f64 - perp_x * offset,
            start.y as f64 - perp_y * offset,
        ),
        pos_from_f64(
            end.x as f64 - perp_x * offset,
            end.y as f64 - perp_y * offset,
        ),
    )
}

fn draw_triple_arc(
    ctx: &mut GameCtx,
    start: EntityPos,
    end: EntityPos,
    width: u64,
    spread: u64,
    color: u32,
) {
    for lane_end in triple_arc_endpoints(start, end, spread) {
        draw_line_band(ctx, start, lane_end, width, color);
    }
    draw_impact_circle(ctx, end, width.max(7000), color);
}

fn draw_cone(
    ctx: &mut GameCtx,
    start: EntityPos,
    target: EntityPos,
    length: u64,
    width_at_end: u64,
    color: u32,
) {
    let dx = target.x as f64 - start.x as f64;
    let dy = target.y as f64 - start.y as f64;
    let len = (dx * dx + dy * dy).sqrt();
    if len <= 0.0 {
        return;
    }

    let dir_x = dx / len;
    let dir_y = dy / len;
    let perp_x = -dir_y;
    let perp_y = dir_x;
    let end_x = start.x as f64 + dir_x * length as f64;
    let end_y = start.y as f64 + dir_y * length as f64;
    let half_width = width_at_end as f64;

    let left = pos_from_f64(end_x + perp_x * half_width, end_y + perp_y * half_width);
    let right = pos_from_f64(end_x - perp_x * half_width, end_y - perp_y * half_width);
    let end = pos_from_f64(end_x, end_y);

    ctx.debug_draw_line(start.x, start.y, left.x, left.y, color);
    ctx.debug_draw_line(start.x, start.y, right.x, right.y, color);
    ctx.debug_draw_line(left.x, left.y, right.x, right.y, color);
    ctx.debug_draw_circle(end.x, end.y, width_at_end / 2, color);
}

fn pos_from_f64(x: f64, y: f64) -> EntityPos {
    EntityPos {
        x: x.clamp(0.0, u64::MAX as f64) as u64,
        y: y.clamp(0.0, u64::MAX as f64) as u64,
    }
}

fn dedenne_play_rough_jungle_safe_end(
    ctx: &GameCtx,
    caster_pos: EntityPos,
    end_pos: EntityPos,
    target_ids: &[usize],
) -> EntityPos {
    const JUNGLE_OVERSHOOT: f64 = 12_000.0;

    if target_ids.iter().any(|target_id| {
        ctx.get_entity(*target_id)
            .map(|target| target.is_champion())
            .unwrap_or(false)
    }) {
        return end_pos;
    }

    let dx = end_pos.x as f64 - caster_pos.x as f64;
    let dy = end_pos.y as f64 - caster_pos.y as f64;
    let len = (dx * dx + dy * dy).sqrt();
    if len <= 0.0 {
        return end_pos;
    }
    let unit_x = dx / len;
    let unit_y = dy / len;

    let mut furthest_jungle_progress: Option<f64> = None;
    for target_id in target_ids {
        if !is_jungle_camp(ctx, *target_id) {
            continue;
        }
        let Some(target) = ctx.get_entity(*target_id) else {
            continue;
        };
        let target_pos = target.pos();
        let progress = (target_pos.x as f64 - caster_pos.x as f64) * unit_x
            + (target_pos.y as f64 - caster_pos.y as f64) * unit_y;
        if progress < 0.0 || progress > len {
            continue;
        }
        if furthest_jungle_progress
            .map(|current| progress > current)
            .unwrap_or(true)
        {
            furthest_jungle_progress = Some(progress);
        }
    }

    let Some(progress) = furthest_jungle_progress else {
        return end_pos;
    };
    let safe_distance = (progress + JUNGLE_OVERSHOOT).min(len);
    if safe_distance >= len {
        return end_pos;
    }

    pos_from_f64(
        caster_pos.x as f64 + unit_x * safe_distance,
        caster_pos.y as f64 + unit_y * safe_distance,
    )
}

