fn collect_enemy_targets(
    ctx: &GameCtx,
    caster_team: usize,
    mut predicate: impl FnMut(EntityPos) -> bool,
) -> Vec<usize> {
    let mut targets = Vec::new();
    for index in 0..ctx.entity_count() {
        let Some(entity) = ctx.entity_at(index) else {
            continue;
        };
        if entity.team() == caster_team
            || !entity.is_alive()
            || !entity.is_targetable()
            || crate::pokemon_status::is_weavile_hidden_from_pokemon_ai(ctx, entity.id())
        {
            continue;
        }
        if predicate(entity.pos()) {
            targets.push(entity.id());
        }
    }
    targets
}

fn chain_dash_targets(
    ctx: &GameCtx,
    caster_team: usize,
    input: InputTarget,
    chain_radius: u64,
    max_targets: usize,
) -> Vec<usize> {
    let InputTarget::Target { target_id } = input else {
        return Vec::new();
    };
    let Some(first) = ctx.get_entity(target_id) else {
        return Vec::new();
    };
    if first.team() == caster_team || !first.is_alive() || !first.is_targetable() {
        return Vec::new();
    }
    if crate::pokemon_status::is_weavile_hidden_from_pokemon_ai(ctx, target_id) {
        return Vec::new();
    }
    let mut current_pos = first.pos();
    drop(first);

    let mut targets = vec![target_id];
    while targets.len() < max_targets {
        let mut best: Option<(u64, usize, EntityPos)> = None;
        for index in 0..ctx.entity_count() {
            let Some(entity) = ctx.entity_at(index) else {
                continue;
            };
            if entity.team() == caster_team
                || !entity.is_alive()
                || !entity.is_targetable()
                || crate::pokemon_status::is_weavile_hidden_from_pokemon_ai(ctx, entity.id())
                || targets.contains(&entity.id())
            {
                continue;
            }
            let dist = distance_sq(entity.pos(), current_pos);
            if dist > chain_radius.saturating_mul(chain_radius) {
                continue;
            }
            if best
                .map(|(best_dist, _, _)| dist < best_dist)
                .unwrap_or(true)
            {
                best = Some((dist, entity.id(), entity.pos()));
            }
        }

        let Some((_, next_id, next_pos)) = best else {
            break;
        };
        targets.push(next_id);
        current_pos = next_pos;
    }

    targets
}

fn target_is_living_ally_champion(ctx: &GameCtx, caster_team: usize, target_id: usize) -> bool {
    ctx.get_entity(target_id)
        .map(|entity| entity.team() == caster_team && entity.is_alive() && entity.is_champion())
        .unwrap_or(false)
}

fn low_health_ally_for_pollen_puff(
    ctx: &GameCtx,
    caster_id: usize,
    caster_team: usize,
    caster_pos: EntityPos,
    radius: u64,
    threshold_percent: usize,
) -> Option<usize> {
    let radius_sq = radius.saturating_mul(radius);
    let mut best: Option<(usize, usize, usize)> = None;

    for index in 0..ctx.entity_count() {
        let Some(entity) = ctx.entity_at(index) else {
            continue;
        };
        if entity.id() == caster_id
            || entity.team() != caster_team
            || !entity.is_champion()
            || !entity.is_alive()
            || distance_sq(entity.pos(), caster_pos) > radius_sq
        {
            continue;
        }

        let hp = entity.hp();
        if hp.max == 0 || hp.current.saturating_mul(100) > hp.max.saturating_mul(threshold_percent)
        {
            continue;
        }

        let candidate = (hp.current, hp.max, entity.id());
        if best
            .map(|(best_current, best_max, _)| {
                hp.current.saturating_mul(best_max) < best_current.saturating_mul(hp.max)
            })
            .unwrap_or(true)
        {
            best = Some(candidate);
        }
    }

    best.map(|(_, _, entity_id)| entity_id)
}

fn apply_pain_split(ctx: &mut GameCtx, caster_id: usize, target_id: usize) {
    let Some(caster) = ctx.get_entity(caster_id) else {
        return;
    };
    let caster_hp = caster.hp().current;
    drop(caster);

    let Some(target) = ctx.get_entity(target_id) else {
        return;
    };
    if !target.is_alive() {
        return;
    }
    let target_hp = target.hp().current;
    drop(target);

    let average = caster_hp.saturating_add(target_hp) / 2;
    if caster_hp > average {
        crate::pokemon_status::deal_tracked_damage(
            ctx,
            target_id,
            caster_id,
            caster_hp.saturating_sub(average),
            0,
            AttackType::Item,
        );
    } else if average > caster_hp {
        crate::pokemon_status::heal_with_antiheal(
            ctx,
            caster_id,
            caster_id,
            average.saturating_sub(caster_hp),
        );
    }

    if target_hp > average {
        crate::pokemon_status::deal_tracked_damage(
            ctx,
            caster_id,
            target_id,
            target_hp.saturating_sub(average),
            0,
            AttackType::Item,
        );
    } else if average > target_hp {
        crate::pokemon_status::heal_with_antiheal(
            ctx,
            caster_id,
            target_id,
            average.saturating_sub(target_hp),
        );
    }
}

fn triple_arc_targets(
    ctx: &GameCtx,
    caster_team: usize,
    caster_pos: EntityPos,
    target_pos: EntityPos,
    width: u64,
    spread: u64,
) -> Vec<usize> {
    let lanes = triple_arc_endpoints(caster_pos, target_pos, spread);
    let width_sq = width.saturating_mul(width);
    collect_enemy_targets(ctx, caster_team, |pos| {
        lanes
            .iter()
            .any(|lane_end| distance_to_segment_sq(pos, caster_pos, *lane_end) <= width_sq)
    })
}

fn triple_arc_endpoints(start: EntityPos, end: EntityPos, spread: u64) -> [EntityPos; 3] {
    let dx = end.x as f64 - start.x as f64;
    let dy = end.y as f64 - start.y as f64;
    let len = (dx * dx + dy * dy).sqrt();
    if len <= 0.0 {
        return [end, end, end];
    }

    let perp_x = -dy / len;
    let perp_y = dx / len;
    let offset = spread as f64;
    [
        end,
        pos_from_f64(
            end.x as f64 + perp_x * offset,
            end.y as f64 + perp_y * offset,
        ),
        pos_from_f64(
            end.x as f64 - perp_x * offset,
            end.y as f64 - perp_y * offset,
        ),
    ]
}

fn triangle_area_centers(start: EntityPos, end: EntityPos, spread: u64) -> [EntityPos; 3] {
    let dx = end.x as f64 - start.x as f64;
    let dy = end.y as f64 - start.y as f64;
    let len = (dx * dx + dy * dy).sqrt();
    if len <= 0.0 {
        return [end, end, end];
    }

    let unit_x = dx / len;
    let unit_y = dy / len;
    let perp_x = -unit_y;
    let perp_y = unit_x;
    let offset = spread as f64;
    [
        pos_from_f64(
            end.x as f64 + unit_x * offset,
            end.y as f64 + unit_y * offset,
        ),
        pos_from_f64(
            end.x as f64 - unit_x * offset / 2.0 + perp_x * offset,
            end.y as f64 - unit_y * offset / 2.0 + perp_y * offset,
        ),
        pos_from_f64(
            end.x as f64 - unit_x * offset / 2.0 - perp_x * offset,
            end.y as f64 - unit_y * offset / 2.0 - perp_y * offset,
        ),
    ]
}

fn bouncing_area_centers(
    start: EntityPos,
    first: EntityPos,
    bounce_distance: u64,
) -> [EntityPos; 3] {
    let dx = first.x as f64 - start.x as f64;
    let dy = first.y as f64 - start.y as f64;
    let len = (dx * dx + dy * dy).sqrt();
    if len <= 0.0 {
        return [first, first, first];
    }
    let unit_x = dx / len;
    let unit_y = dy / len;
    let step = bounce_distance as f64;
    [
        first,
        pos_from_f64(
            first.x as f64 + unit_x * step,
            first.y as f64 + unit_y * step,
        ),
        pos_from_f64(
            first.x as f64 + unit_x * step * 2.0,
            first.y as f64 + unit_y * step * 2.0,
        ),
    ]
}

fn distance_sq(a: EntityPos, b: EntityPos) -> u64 {
    let dx = a.x as i128 - b.x as i128;
    let dy = a.y as i128 - b.y as i128;
    squared_len_i128(dx, dy).min(u64::MAX as i128) as u64
}

fn squared_len_i128(dx: i128, dy: i128) -> i128 {
    dx.checked_mul(dx)
        .and_then(|x2| dy.checked_mul(dy).and_then(|y2| x2.checked_add(y2)))
        .unwrap_or(i128::MAX)
}

fn squared_i128(value: i128) -> i128 {
    value.checked_mul(value).unwrap_or(i128::MAX)
}

fn is_in_octagon(point: EntityPos, center: EntityPos, radius: u64) -> bool {
    let radius = radius as i128;
    let diag = radius.saturating_mul(707) / 1000;
    let vertices = [
        (radius, 0),
        (diag, diag),
        (0, radius),
        (-diag, diag),
        (-radius, 0),
        (-diag, -diag),
        (0, -radius),
        (diag, -diag),
    ];
    let px = point.x as i128 - center.x as i128;
    let py = point.y as i128 - center.y as i128;

    vertices
        .iter()
        .zip(vertices.iter().cycle().skip(1))
        .take(vertices.len())
        .all(|(&(ax, ay), &(bx, by))| {
            let edge_x = bx - ax;
            let edge_y = by - ay;
            let point_x = px - ax;
            let point_y = py - ay;
            edge_x * point_y - edge_y * point_x >= 0
        })
}

fn integer_sqrt(value: u64) -> u64 {
    (value as f64).sqrt() as u64
}

fn distance_to_segment_sq(point: EntityPos, start: EntityPos, end: EntityPos) -> u64 {
    let px = point.x as i128;
    let py = point.y as i128;
    let ax = start.x as i128;
    let ay = start.y as i128;
    let bx = end.x as i128;
    let by = end.y as i128;
    let abx = bx - ax;
    let aby = by - ay;
    let apx = px - ax;
    let apy = py - ay;
    let ab_len_sq = squared_len_i128(abx, aby);

    if ab_len_sq <= 0 {
        return distance_sq(point, start);
    }

    let t_num = (apx * abx + apy * aby).clamp(0, ab_len_sq);
    let closest_x_num = ax * ab_len_sq + abx * t_num;
    let closest_y_num = ay * ab_len_sq + aby * t_num;
    let dx_num = px * ab_len_sq - closest_x_num;
    let dy_num = py * ab_len_sq - closest_y_num;
    let Some(denominator) = ab_len_sq.checked_mul(ab_len_sq) else {
        return distance_sq(point, start);
    };
    if denominator <= 0 {
        return distance_sq(point, start);
    }

    let dist_sq = squared_len_i128(dx_num, dy_num) / denominator;
    dist_sq.min(u64::MAX as i128) as u64
}

fn is_inside_cone(
    point: EntityPos,
    start: EntityPos,
    target: EntityPos,
    length: u64,
    width_at_end: u64,
) -> bool {
    let px = point.x as i128;
    let py = point.y as i128;
    let sx = start.x as i128;
    let sy = start.y as i128;
    let tx = target.x as i128;
    let ty = target.y as i128;
    let dir_x = tx - sx;
    let dir_y = ty - sy;
    let dir_len_sq = squared_len_i128(dir_x, dir_y);
    if dir_len_sq <= 0 {
        return false;
    }

    let point_x = px - sx;
    let point_y = py - sy;
    let projection_num = point_x * dir_x + point_y * dir_y;
    if projection_num <= 0 {
        return false;
    }

    let projection_sq_scaled = squared_i128(projection_num) / dir_len_sq;
    if projection_sq_scaled > (length as i128) * (length as i128) {
        return false;
    }

    let cross = point_x * dir_y - point_y * dir_x;
    let perpendicular_sq_scaled = squared_i128(cross) / dir_len_sq;
    let width_num = (width_at_end as i128) * projection_num;
    let Some(width_denominator) = dir_len_sq.checked_mul(dir_len_sq) else {
        return false;
    };
    if width_denominator <= 0 {
        return false;
    }
    let allowed_width_sq_scaled = squared_i128(width_num) / width_denominator;
    perpendicular_sq_scaled <= allowed_width_sq_scaled
}

fn is_inside_melee_arc(
    point: EntityPos,
    start: EntityPos,
    target: EntityPos,
    range: u64,
    width_at_edge: u64,
) -> bool {
    is_inside_cone(point, start, target, range, width_at_edge)
}

fn is_inside_cast_rectangle(
    point: EntityPos,
    start: EntityPos,
    target: EntityPos,
    length: u64,
    width: u64,
) -> bool {
    let dx = target.x as f64 - start.x as f64;
    let dy = target.y as f64 - start.y as f64;
    let len = (dx * dx + dy * dy).sqrt();
    if len <= 0.0 {
        return false;
    }

    let end = pos_from_f64(
        start.x as f64 + dx / len * length as f64,
        start.y as f64 + dy / len * length as f64,
    );
    let ax = start.x as i128;
    let ay = start.y as i128;
    let bx = end.x as i128;
    let by = end.y as i128;
    let px = point.x as i128;
    let py = point.y as i128;
    let abx = bx - ax;
    let aby = by - ay;
    let ab_len_sq = abx * abx + aby * aby;
    if ab_len_sq == 0 {
        return false;
    }

    let projection = (px - ax) * abx + (py - ay) * aby;
    if projection < 0 || projection > ab_len_sq {
        return false;
    }

    distance_to_segment_sq(point, start, end) <= (width / 2).saturating_mul(width / 2)
}

fn first_enemy_on_line(
    ctx: &GameCtx,
    caster_team: usize,
    start: EntityPos,
    end: EntityPos,
    width: u64,
) -> Option<usize> {
    let ax = start.x as i128;
    let ay = start.y as i128;
    let bx = end.x as i128;
    let by = end.y as i128;
    let abx = bx - ax;
    let aby = by - ay;
    let ab_len_sq = abx * abx + aby * aby;
    if ab_len_sq == 0 {
        return None;
    }

    let mut best: Option<(i128, usize)> = None;
    for index in 0..ctx.entity_count() {
        let Some(entity) = ctx.entity_at(index) else {
            continue;
        };
        if entity.team() == caster_team
            || !entity.is_alive()
            || !entity.is_targetable()
            || crate::pokemon_status::is_weavile_hidden_from_pokemon_ai(ctx, entity.id())
        {
            continue;
        }

        let pos = entity.pos();
        if distance_to_segment_sq(pos, start, end) > width.saturating_mul(width) {
            continue;
        }

        let px = pos.x as i128;
        let py = pos.y as i128;
        let projection = (px - ax) * abx + (py - ay) * aby;
        if projection < 0 || projection > ab_len_sq {
            continue;
        }

        if best
            .map(|(best_projection, _)| projection < best_projection)
            .unwrap_or(true)
        {
            best = Some((projection, entity.id()));
        }
    }

    best.map(|(_, entity_id)| entity_id)
}

#[allow(clippy::too_many_arguments)]
fn apply_marowak_bonemerang(
    ctx: &mut GameCtx,
    caster_id: usize,
    caster_team: usize,
    caster_pos: EntityPos,
    caster_stat: EntityStat,
    champion_id: &str,
    action: PokemonMove,
    input: InputTarget,
    base_ad: usize,
    ad_ratio: usize,
    width: u64,
    travel_range: u64,
    empowered_range_percent: usize,
    empowered_speed_percent: usize,
    empowered_missing_hp_percent: usize,
    rhythm_attack_speed_mult: i32,
    rhythm_ticks: usize,
    attacker_types: TypeSet,
) {
    let empowered = crate::pokemon_status::consume_marowak_windmill_bonemerang(ctx, caster_id);
    let travel_range = if empowered {
        travel_range.saturating_mul(100usize.saturating_add(empowered_range_percent) as u64) / 100
    } else {
        travel_range
    };
    let Some(end_pos) = traveling_wave_end(ctx, input, caster_pos, travel_range) else {
        return;
    };
    let targets = collect_enemy_targets(ctx, caster_team, |pos| {
        distance_to_segment_sq(pos, caster_pos, end_pos) <= width.saturating_mul(width)
    });
    draw_line_band(
        ctx,
        caster_pos,
        end_pos,
        width,
        type_debug_color(PokemonType::Ground),
    );
    draw_line_band(
        ctx,
        end_pos,
        caster_pos,
        width / 2,
        type_debug_color(PokemonType::Ground),
    );

    let base_damage = base_ad.saturating_add(caster_stat.attack.saturating_mul(ad_ratio) / 100);
    let mut landed = false;
    let mut hit_index = 0usize;
    for target_id in targets.iter().copied().chain(targets.iter().rev().copied()) {
        let actual_target_id =
            crate::pokemon_status::audino_protect_redirect(ctx, target_id).unwrap_or(target_id);
        if crate::pokemon_status::consume_detect_guard(ctx, actual_target_id) {
            hit_index = hit_index.saturating_add(1);
            continue;
        }

        let mut hit_ad_damage = base_damage;
        if empowered {
            let missing_hp = ctx
                .get_entity(actual_target_id)
                .map(|target| target.hp().max.saturating_sub(target.hp().current))
                .unwrap_or(0);
            hit_ad_damage = hit_ad_damage
                .saturating_add(missing_hp.saturating_mul(empowered_missing_hp_percent) / 100);
        }
        let crit_chance = caster_stat.crit_chance;
        let (hit_ad_damage, _) = apply_basic_attack_crit(
            ctx,
            champion_id,
            action,
            PokemonMoveEffect::MarowakBonemerang {
                base_ad,
                ad_ratio,
                width,
                travel_range,
                empowered_range_percent,
                empowered_speed_percent,
                empowered_missing_hp_percent,
                rhythm_attack_speed_mult,
                rhythm_ticks,
            },
            crit_chance,
            caster_id,
            actual_target_id,
            hit_index,
            hit_ad_damage,
            0,
        );
        let defender_types = effective_defender_types(ctx, actual_target_id, PokemonType::Ground);
        crate::pokemon_status::note_physical_basic_hit(ctx, caster_id, actual_target_id);
        let result = deal_or_volt_absorb_pokemon_damage(
            ctx,
            caster_id,
            actual_target_id,
            hit_ad_damage.max(1),
            0,
            AttackType::BaseAttack,
            PokemonType::Ground,
            attacker_types,
            defender_types,
        );
        if result.applied_damage > 0 {
            landed = true;
        }
        hit_index = hit_index.saturating_add(1);
    }

    if landed {
        let attack_speed_mult = if empowered {
            rhythm_attack_speed_mult.saturating_add(empowered_speed_percent as i32)
        } else {
            rhythm_attack_speed_mult
        };
        crate::pokemon_status::add_beneficial_buff(
            ctx,
            caster_id,
            caster_id,
            BuffState {
                duration: BuffType::Time { tick: rhythm_ticks },
                attack_speed_mult,
                ..Default::default()
            },
        );
    }
}

#[allow(clippy::too_many_arguments)]
fn apply_marowak_bone_rush(
    ctx: &mut GameCtx,
    caster_id: usize,
    caster_team: usize,
    caster_pos: EntityPos,
    caster_stat: EntityStat,
    champion_id: &str,
    _action: PokemonMove,
    input: InputTarget,
    first_base_ad: usize,
    first_ad_ratio: usize,
    second_base_ad: usize,
    second_ad_ratio: usize,
    third_base_ad: usize,
    third_ad_ratio: usize,
    second_chance_percent: usize,
    third_chance_percent: usize,
    stun_ticks: usize,
    width: u64,
    force_move_speed: u64,
    force_move_ticks: u64,
    attacker_types: TypeSet,
) {
    let Some(target_pos) = input_position(ctx, input) else {
        return;
    };
    let Some(target_id) =
        first_enemy_on_line_non_tower(ctx, caster_team, caster_pos, target_pos, width)
    else {
        draw_line_band(
            ctx,
            caster_pos,
            target_pos,
            width,
            type_debug_color(PokemonType::Ground),
        );
        return;
    };
    let Some(contact_pos) = ctx.get_entity(target_id).map(|target| target.pos()) else {
        return;
    };
    apply_force_move_toward_pos_bounded(
        ctx,
        caster_id,
        caster_pos,
        contact_pos,
        force_move_speed,
        force_move_ticks,
    );
    apply_limber_aware_stun(ctx, caster_id, target_id, stun_ticks as u64);
    crate::pokemon_status::apply_pokemon_cc(
        ctx,
        caster_id,
        caster_id,
        CCState::Bind {
            tick: force_move_ticks.saturating_add(stun_ticks as u64 / 2),
        },
    );
    draw_line_band(
        ctx,
        caster_pos,
        contact_pos,
        width,
        type_debug_color(PokemonType::Ground),
    );

    let hit_specs = [
        (first_base_ad, first_ad_ratio, true),
        (
            second_base_ad,
            second_ad_ratio,
            chance_percent(
                ctx.seed() ^ 0xb01e_2002_u64,
                caster_id,
                target_id,
                ctx.tick(),
                second_chance_percent,
            ),
        ),
        (third_base_ad, third_ad_ratio, false),
    ];
    let mut second_landed = false;
    for (index, (base, ratio, should_land)) in hit_specs.iter().copied().enumerate() {
        let should_land = if index == 2 {
            second_landed
                && chance_percent(
                    ctx.seed() ^ 0xb01e_3003_u64,
                    caster_id,
                    target_id,
                    ctx.tick().saturating_add(index),
                    third_chance_percent,
                )
        } else {
            should_land
        };
        if !should_land {
            break;
        }
        if index == 1 {
            second_landed = true;
        }
        let actual_target_id =
            crate::pokemon_status::audino_protect_redirect(ctx, target_id).unwrap_or(target_id);
        if crate::pokemon_status::consume_detect_guard(ctx, actual_target_id) {
            continue;
        }
        let mut damage = base.saturating_add(caster_stat.attack.saturating_mul(ratio) / 100);
        if index == 2 && !crate::pokemon_status::has_shell_armor(ctx, actual_target_id) {
            let crit_percent = crate::pokemon_status::adjust_incoming_critical_damage_percent(
                ctx,
                actual_target_id,
                crit_damage_percent(caster_id, champion_id, caster_stat.crit_chance.max(100)),
            );
            damage = damage.saturating_mul(crit_percent) / 100;
        }
        let defender_types = effective_defender_types(ctx, actual_target_id, PokemonType::Ground);
        deal_or_volt_absorb_pokemon_damage(
            ctx,
            caster_id,
            actual_target_id,
            damage.max(1),
            0,
            AttackType::Skill,
            PokemonType::Ground,
            attacker_types,
            defender_types,
        );
    }
}

#[allow(clippy::too_many_arguments)]
fn apply_garganacl_land_crush(
    ctx: &mut GameCtx,
    caster_id: usize,
    caster_team: usize,
    caster_pos: EntityPos,
    caster_stat: EntityStat,
    input: InputTarget,
    base_ad: usize,
    ad_ratio: usize,
    travel_range: u64,
    width: u64,
    salt_slow_percent: i32,
    salt_slow_ticks: usize,
    attacker_types: TypeSet,
) {
    let Some(end_pos) = traveling_wave_end(ctx, input, caster_pos, travel_range) else {
        return;
    };
    draw_line_band(
        ctx,
        caster_pos,
        end_pos,
        width,
        type_debug_color(PokemonType::Rock),
    );
    let damage = base_ad.saturating_add(caster_stat.attack.saturating_mul(ad_ratio) / 100);
    let targets = collect_enemy_targets(ctx, caster_team, |pos| {
        distance_to_segment_sq(pos, caster_pos, end_pos) <= width.saturating_mul(width)
    });
    for target_id in targets {
        let actual_target_id =
            crate::pokemon_status::audino_protect_redirect(ctx, target_id).unwrap_or(target_id);
        if crate::pokemon_status::consume_detect_guard(ctx, actual_target_id) {
            continue;
        }
        let defender_types =
            crate::neutral_objectives::defender_types_for_target(ctx, actual_target_id);
        deal_or_volt_absorb_pokemon_damage(
            ctx,
            caster_id,
            actual_target_id,
            damage.max(1),
            0,
            AttackType::Skill,
            PokemonType::Rock,
            attacker_types,
            defender_types,
        );
        if crate::pokemon_status::garganacl_entity_in_salt(ctx, actual_target_id) {
            crate::pokemon_status::add_harmful_buff(
                ctx,
                caster_id,
                actual_target_id,
                BuffState {
                    duration: BuffType::Time {
                        tick: salt_slow_ticks,
                    },
                    move_speed_mult: -salt_slow_percent,
                    ..Default::default()
                },
            );
        }
    }
}

fn first_enemy_on_line_non_tower(
    ctx: &GameCtx,
    caster_team: usize,
    start: EntityPos,
    end: EntityPos,
    width: u64,
) -> Option<usize> {
    let ax = start.x as i128;
    let ay = start.y as i128;
    let bx = end.x as i128;
    let by = end.y as i128;
    let abx = bx - ax;
    let aby = by - ay;
    let ab_len_sq = abx * abx + aby * aby;
    if ab_len_sq == 0 {
        return None;
    }

    let mut best: Option<(i128, usize)> = None;
    for index in 0..ctx.entity_count() {
        let Some(entity) = ctx.entity_at(index) else {
            continue;
        };
        if entity.team() == caster_team
            || !entity.is_alive()
            || !entity.is_targetable()
            || entity.is_tower()
            || crate::pokemon_status::is_weavile_hidden_from_pokemon_ai(ctx, entity.id())
        {
            continue;
        }
        if distance_to_segment_sq(entity.pos(), start, end) > width.saturating_mul(width) {
            continue;
        }
        let projection = (entity.pos().x as i128 - ax) * abx + (entity.pos().y as i128 - ay) * aby;
        if projection < 0 || projection > ab_len_sq {
            continue;
        }
        if best
            .map(|(best_projection, _)| projection < best_projection)
            .unwrap_or(true)
        {
            best = Some((projection, entity.id()));
        }
    }
    best.map(|(_, entity_id)| entity_id)
}

fn tangling_vines_amp(
    ctx: &GameCtx,
    caster_team: usize,
    caster_pos: EntityPos,
    target_id: usize,
) -> bool {
    if !crate::pokemon_status::is_crowd_controlled(ctx, target_id) {
        return false;
    }

    for index in 0..ctx.entity_count() {
        let Some(entity) = ctx.entity_at(index) else {
            continue;
        };
        if entity.team() != caster_team || !entity.is_alive() {
            continue;
        }
        if crate::pokemon_status::entity_types(entity.id())
            != Some(TypeSet::dual(PokemonType::Grass, PokemonType::Poison))
        {
            continue;
        }
        if distance_sq(entity.pos(), caster_pos) <= 70000_u64.saturating_mul(70000) {
            return true;
        }
    }

    false
}

