fn apply_dragapult_dragon_launcher(
    ctx: &mut GameCtx,
    caster_id: usize,
    target_id: usize,
    caster_stat: EntityStat,
    active_attacker_types: TypeSet,
) {
    let Some(target_pos) = ctx.get_entity(target_id).map(|target| target.pos()) else {
        return;
    };
    let caster_pos = ctx
        .get_entity(caster_id)
        .map(|caster| caster.pos())
        .unwrap_or(target_pos);
    let damage = 14usize
        .saturating_add(caster_stat.attack.saturating_mul(12) / 100)
        .saturating_add(caster_stat.magic_power.saturating_mul(12) / 100);
    let defender_types = effective_defender_types(ctx, target_id, PokemonType::Ghost);
    let result = deal_or_volt_absorb_pokemon_damage(
        ctx,
        caster_id,
        target_id,
        0,
        damage.max(1),
        AttackType::Skill,
        PokemonType::Ghost,
        active_attacker_types,
        defender_types,
    );
    let heal = result.applied_damage.saturating_mul(35) / 100;
    if heal > 0 {
        crate::pokemon_status::heal_from_damage_or_poison_yanmega(
            ctx,
            caster_id,
            target_id,
            heal,
        );
    }
    draw_line_band(
        ctx,
        caster_pos,
        target_pos,
        2500,
        type_debug_color(PokemonType::Ghost),
    );
}

fn note_magmortar_basic_hit(
    ctx: &mut GameCtx,
    caster_id: usize,
    caster_team: usize,
    target_id: usize,
    caster_stat: EntityStat,
    attacker_types: TypeSet,
) {
    let tick = ctx.tick();
    let states = MAGMORTAR_BASICS.get_or_init(|| Mutex::new(Vec::new()));
    let mut states = states.lock().expect("magmortar basic state poisoned");
    states.retain(|state| tick.saturating_sub(state.last_hit_at) <= 6 * 60);
    let state = if let Some(index) = states
        .iter()
        .position(|state| state.caster_id == caster_id && state.target_id == target_id)
    {
        &mut states[index]
    } else {
        states.push(MagmortarBasicState {
            caster_id,
            target_id,
            hits: 0,
            last_hit_at: tick,
        });
        states.last_mut().expect("magmortar basic state missing")
    };
    if tick.saturating_sub(state.last_hit_at) > 6 * 60 {
        state.hits = 0;
    }
    state.hits = state.hits.saturating_add(1);
    state.last_hit_at = tick;
    let hits = state.hits;
    if hits % 4 != 0 {
        return;
    }
    drop(states);

    let Some(target) = ctx.get_entity(target_id) else {
        return;
    };
    let target_hp = target.hp();
    let target_pos = target.pos();
    drop(target);
    let percent = if ctx
        .get_entity(caster_id)
        .map(|entity| entity.level())
        .unwrap_or(1)
        >= 9
    {
        10
    } else if ctx
        .get_entity(caster_id)
        .map(|entity| entity.level())
        .unwrap_or(1)
        >= 5
    {
        8
    } else {
        6
    };
    let max_hp_damage = target_hp.max.saturating_mul(percent) / 100;
    let defender_types = effective_defender_types(ctx, target_id, PokemonType::Fire);
    deal_or_volt_absorb_pokemon_damage(
        ctx,
        caster_id,
        target_id,
        max_hp_damage.max(1),
        0,
        AttackType::BaseAttack,
        PokemonType::Fire,
        attacker_types,
        defender_types,
    );
    let grounds = MAGMORTAR_BURNING_GROUNDS.get_or_init(|| Mutex::new(Vec::new()));
    let mut grounds = grounds
        .lock()
        .expect("magmortar burning ground state poisoned");
    grounds.push(MagmortarBurningGroundState {
        caster_id,
        caster_team,
        center: target_pos,
        radius: 15000,
        expires_at: tick.saturating_add(3 * 60),
        next_tick_at: tick,
        tick_interval: 30,
        damage: 20 + caster_stat.attack.saturating_mul(10) / 100,
        attacker_types,
    });
}

fn tiered_level_value(level: usize, low: usize, mid: usize, high: usize) -> usize {
    if level >= 9 {
        high
    } else if level >= 5 {
        mid
    } else {
        low
    }
}

fn tiered_level_i32(level: usize, low: i32, mid: i32, high: i32) -> i32 {
    if level >= 9 {
        high
    } else if level >= 5 {
        mid
    } else {
        low
    }
}

fn begin_shell_traps(
    ctx: &GameCtx,
    caster_id: usize,
    caster_team: usize,
    centers: [EntityPos; 3],
    radius: u64,
    ad_damage: usize,
    duration_ticks: usize,
    slow_percent: i32,
    slow_ticks: usize,
) {
    let tick = ctx.tick();
    let traps = SHELL_TRAPS.get_or_init(|| Mutex::new(Vec::new()));
    let mut traps = traps.lock().expect("shell trap state poisoned");
    for center in centers {
        traps.push(ShellTrapState {
            caster_id,
            caster_team,
            center,
            radius,
            ad_damage,
            expires_at: tick.saturating_add(duration_ticks),
            slow_percent,
            slow_ticks,
        });
    }
}

fn update_shell_traps(ctx: &mut GameCtx) {
    let tick = ctx.tick();
    {
        let last_tick = SHELL_TRAP_LAST_TICK.get_or_init(|| Mutex::new(usize::MAX));
        let mut last_tick = last_tick.lock().expect("shell trap tick state poisoned");
        if *last_tick == tick {
            return;
        }
        *last_tick = tick;
    }

    let mut triggered: Vec<(ShellTrapState, usize)> = Vec::new();
    {
        let traps = SHELL_TRAPS.get_or_init(|| Mutex::new(Vec::new()));
        let mut traps = traps.lock().expect("shell trap state poisoned");
        traps.retain(|trap| {
            trap.expires_at > tick
                && ctx
                    .get_entity(trap.caster_id)
                    .map(|caster| caster.is_alive())
                    .unwrap_or(false)
        });

        let mut index = 0;
        while index < traps.len() {
            let trap = traps[index];
            let target = first_enemy_in_radius(ctx, trap.caster_team, trap.center, trap.radius);
            if let Some(target_id) = target {
                triggered.push((trap, target_id));
                traps.remove(index);
            } else {
                index += 1;
            }
        }
    }

    for (trap, target_id) in triggered {
        let defender_types = effective_defender_types(ctx, target_id, PokemonType::Fire);
        deal_or_volt_absorb_pokemon_damage(
            ctx,
            trap.caster_id,
            target_id,
            trap.ad_damage.max(1),
            0,
            AttackType::Skill,
            PokemonType::Fire,
            TypeSet::dual(PokemonType::Fire, PokemonType::Dragon),
            defender_types,
        );
        ctx.add_buff(
            target_id,
            BuffState {
                duration: BuffType::Time {
                    tick: trap.slow_ticks,
                },
                move_speed_mult: -trap.slow_percent.abs(),
                ..Default::default()
            },
        );
        draw_impact_circle(
            ctx,
            trap.center,
            trap.radius,
            type_debug_color(PokemonType::Fire),
        );
    }
}

fn begin_sunny_day(
    ctx: &GameCtx,
    caster_id: usize,
    caster_team: usize,
    start: EntityPos,
    target: EntityPos,
    duration_ticks: usize,
    length: u64,
    width: u64,
    slow_percent: i32,
    slow_ticks: usize,
    damage_bonus_percent: usize,
    status_bonus_percent: usize,
) {
    let tick = ctx.tick();
    let fields = SUNNY_DAYS.get_or_init(|| Mutex::new(Vec::new()));
    let mut fields = fields.lock().expect("sunny day state poisoned");
    fields.retain(|field| field.caster_id != caster_id);
    fields.push(SunnyDayState {
        caster_id,
        caster_team,
        start,
        target,
        length,
        width,
        expires_at: tick.saturating_add(duration_ticks),
        next_tick_at: tick,
        slow_percent,
        slow_ticks,
        damage_bonus_percent,
        status_bonus_percent,
    });
}

fn update_sunny_days(ctx: &mut GameCtx) {
    let tick = ctx.tick();
    {
        let last_tick = SUNNY_DAY_LAST_TICK.get_or_init(|| Mutex::new(usize::MAX));
        let mut last_tick = last_tick.lock().expect("sunny day tick state poisoned");
        if *last_tick == tick {
            return;
        }
        *last_tick = tick;
    }

    let mut slows = Vec::new();
    {
        let fields = SUNNY_DAYS.get_or_init(|| Mutex::new(Vec::new()));
        let mut fields = fields.lock().expect("sunny day state poisoned");
        fields.retain(|field| {
            field.expires_at > tick
                && ctx
                    .get_entity(field.caster_id)
                    .map(|caster| caster.is_alive())
                    .unwrap_or(false)
        });
        for field in fields.iter_mut() {
            if field.next_tick_at > tick {
                continue;
            }
            field.next_tick_at = tick.saturating_add(30);
            for target_id in collect_enemy_targets(ctx, field.caster_team, |pos| {
                is_inside_cast_rectangle(pos, field.start, field.target, field.length, field.width)
            }) {
                if sunny_day_slow_exempt(ctx, target_id) {
                    continue;
                }
                slows.push((target_id, field.slow_percent, field.slow_ticks));
            }
        }
    }

    for (target_id, slow_percent, slow_ticks) in slows {
        ctx.add_buff(
            target_id,
            BuffState {
                duration: BuffType::Time { tick: slow_ticks },
                move_speed_mult: -slow_percent.abs(),
                ..Default::default()
            },
        );
    }
}

fn sunny_day_slow_exempt(ctx: &GameCtx, target_id: usize) -> bool {
    crate::neutral_objectives::defender_types_for_target(ctx, target_id)
        .iter()
        .any(|pokemon_type| {
            matches!(
                pokemon_type,
                PokemonType::Fire | PokemonType::Electric | PokemonType::Grass
            )
        })
}

fn sunny_day_boosted_type(move_type: PokemonType) -> bool {
    matches!(
        move_type,
        PokemonType::Fire | PokemonType::Electric | PokemonType::Grass
    )
}

fn sunny_day_bonus_for_target(
    ctx: &GameCtx,
    target_id: usize,
    move_type: PokemonType,
) -> Option<(usize, usize)> {
    if !sunny_day_boosted_type(move_type) {
        return None;
    }
    let target_pos = ctx.get_entity(target_id).map(|target| target.pos())?;
    let tick = ctx.tick();
    SUNNY_DAYS
        .get_or_init(|| Mutex::new(Vec::new()))
        .lock()
        .expect("sunny day state poisoned")
        .iter()
        .filter(|field| field.expires_at > tick)
        .find(|field| {
            is_inside_cast_rectangle(
                target_pos,
                field.start,
                field.target,
                field.length,
                field.width,
            )
        })
        .map(|field| (field.damage_bonus_percent, field.status_bonus_percent))
}

