fn apply_ribombee_rescue(
    ctx: &mut GameCtx,
    caster_id: usize,
    target_id: usize,
    speed: u64,
    ticks: u64,
    block_ticks: usize,
) {
    let Some(caster) = ctx.get_entity(caster_id) else {
        return;
    };
    let caster_team = caster.team();
    let caster_pos = caster.pos();
    drop(caster);

    let Some(target) = ctx.get_entity(target_id) else {
        return;
    };
    if target.team() != caster_team || !target.is_alive() || !target.is_champion() {
        return;
    }
    let target_pos = target.pos();
    drop(target);

    apply_force_move_toward_pos(ctx, caster_id, caster_pos, target_pos, speed, ticks / 2);

    let away_from = closest_enemy_target(ctx, caster_team, target_pos)
        .and_then(|enemy_id| ctx.get_entity(enemy_id).map(|enemy| enemy.pos()))
        .unwrap_or(caster_pos);
    apply_force_move_away_from_pos(ctx, caster_id, target_pos, away_from, speed, ticks);
    apply_force_move_away_from_pos(ctx, target_id, target_pos, away_from, speed, ticks);
    crate::pokemon_status::apply_pokemon_cc(
        ctx,
        caster_id,
        target_id,
        CCState::Airborne {
            tick: block_ticks as u64,
        },
    );
    crate::pokemon_status::apply_pokemon_cc(ctx, caster_id, target_id, CCState::BlockSkill { tick: block_ticks });
    crate::pokemon_status::apply_pokemon_cc(ctx, caster_id, target_id, CCState::BlockAttack { tick: block_ticks });
    draw_line_band(
        ctx,
        caster_pos,
        target_pos,
        6500,
        type_debug_color(PokemonType::Bug),
    );
}

fn apply_shadow_sneak_displacement(
    ctx: &mut GameCtx,
    caster_id: usize,
    target_id: usize,
    speed: u64,
    tick: u64,
) {
    let Some(caster) = ctx.get_entity(caster_id) else {
        return;
    };
    let Some(target) = ctx.get_entity(target_id) else {
        return;
    };
    let caster_pos = caster.pos();
    let target_pos = target.pos();
    drop(caster);
    drop(target);

    apply_airborne_force_move_toward_pos(ctx, caster_id, caster_pos, target_pos, speed, tick);
    if stalwart_blocks_force_move(ctx, caster_id, target_id) {
        return;
    }
    apply_airborne_force_move_toward_pos(ctx, target_id, target_pos, caster_pos, speed, tick);
}

fn bounded_force_move_speed(speed: u64, tick: u64, distance: u64) -> u64 {
    if speed == 0 || tick == 0 || distance == 0 {
        return 0;
    }
    let speed_to_cover_distance = distance
        .saturating_add(tick.saturating_sub(1))
        .saturating_div(tick)
        .max(1);
    speed.min(speed_to_cover_distance)
}

fn apply_audino_substitute_displacement(
    ctx: &mut GameCtx,
    caster_id: usize,
    target_id: usize,
    speed: u64,
    tick: u64,
) {
    let Some(caster) = ctx.get_entity(caster_id) else {
        return;
    };
    let Some(target) = ctx.get_entity(target_id) else {
        return;
    };
    if !target.is_alive() || caster.team() != target.team() {
        return;
    }
    let caster_pos = caster.pos();
    let target_pos = target.pos();
    drop(caster);
    drop(target);

    apply_airborne_force_move_toward_pos(ctx, caster_id, caster_pos, target_pos, speed, tick);
    apply_airborne_force_move_toward_pos(ctx, target_id, target_pos, caster_pos, speed, tick);
}

fn apply_phantom_force_splash_on_kill(
    ctx: &mut GameCtx,
    caster_id: usize,
    caster_team: usize,
    target_id: usize,
    base_damage: usize,
    radius: u64,
    splash_percent: usize,
    move_type: PokemonType,
    attacker_types: TypeSet,
) {
    let Some(target) = ctx.get_entity(target_id) else {
        return;
    };
    if target.is_alive() {
        return;
    }
    let center = target.pos();
    drop(target);

    let splash_damage = base_damage.saturating_mul(splash_percent) / 100;
    if splash_damage == 0 {
        return;
    }

    let splash_targets = collect_enemy_targets(ctx, caster_team, |pos| {
        distance_sq(pos, center) <= radius.saturating_mul(radius)
    });
    for splash_target_id in splash_targets {
        if splash_target_id == target_id {
            continue;
        }
        let defender_types = effective_defender_types(ctx, splash_target_id, move_type);
        deal_or_volt_absorb_pokemon_damage(
            ctx,
            caster_id,
            splash_target_id,
            splash_damage,
            0,
            AttackType::Skill,
            move_type,
            attacker_types,
            defender_types,
        );
    }
}

fn apply_stat_steal(
    ctx: &mut GameCtx,
    caster_id: usize,
    target_id: usize,
    stat_percent: i32,
    ticks: usize,
) {
    if caster_id == target_id || stat_percent == 0 || ticks == 0 {
        return;
    }
    let roll = splitmix64(
        ctx.seed() ^ ((caster_id as u64) << 32) ^ ((target_id as u64) << 12) ^ ctx.tick() as u64,
    ) % 6;
    let mut stolen = BuffState {
        duration: BuffType::Time { tick: ticks },
        ..Default::default()
    };
    let mut loss = BuffState {
        duration: BuffType::Time { tick: ticks },
        ..Default::default()
    };
    match roll {
        0 => {
            stolen.attack_mult = stat_percent;
            loss.attack_mult = -stat_percent;
        }
        1 => {
            stolen.attack_speed_mult = stat_percent;
            loss.attack_speed_mult = -stat_percent;
        }
        2 => {
            stolen.crit_chance = stat_percent;
            loss.crit_chance = -stat_percent;
        }
        3 => {
            stolen.defence_mult = stat_percent;
            loss.defence_mult = -stat_percent;
        }
        4 => {
            stolen.magic_resistance_mult = stat_percent;
            loss.magic_resistance_mult = -stat_percent;
        }
        _ => {
            stolen.move_speed_mult = stat_percent;
            loss.move_speed_mult = -stat_percent;
        }
    }
    crate::pokemon_status::add_beneficial_buff(ctx, caster_id, caster_id, stolen);
    crate::pokemon_status::add_harmful_buff(ctx, caster_id, target_id, loss);
}

fn apply_poltergeist_damage(
    ctx: &mut GameCtx,
    caster_id: usize,
    target_id: usize,
    damage_percent: usize,
    attacker_types: TypeSet,
) {
    let Some(target) = ctx.get_entity(target_id) else {
        return;
    };
    if !target.is_alive() {
        return;
    }
    let target_stat = target.stat();
    let level = target.level();
    drop(target);

    let Some(champion_id) = crate::pokemon_status::champion_id_for_entity(target_id) else {
        return;
    };
    let Some(base_stat) = champion_base_stat_for_level(champion_id, level) else {
        return;
    };

    let mut candidates: Vec<(usize, usize)> = Vec::new();
    push_poltergeist_candidate(
        &mut candidates,
        target_stat.attack.saturating_sub(base_stat.attack),
        damage_percent,
        true,
        1,
    );
    push_poltergeist_candidate(
        &mut candidates,
        target_stat
            .magic_power
            .saturating_sub(base_stat.magic_power),
        damage_percent,
        false,
        1,
    );
    push_poltergeist_candidate(
        &mut candidates,
        target_stat.hp.saturating_sub(base_stat.hp),
        damage_percent,
        true,
        4,
    );
    push_poltergeist_candidate(
        &mut candidates,
        target_stat.defence.saturating_sub(base_stat.defence),
        damage_percent,
        true,
        1,
    );
    push_poltergeist_candidate(
        &mut candidates,
        target_stat
            .magic_resistance
            .saturating_sub(base_stat.magic_resistance),
        damage_percent,
        false,
        1,
    );
    push_poltergeist_candidate(
        &mut candidates,
        target_stat.move_speed.saturating_sub(base_stat.move_speed),
        damage_percent,
        true,
        8,
    );
    push_poltergeist_candidate(
        &mut candidates,
        target_stat
            .crit_chance
            .saturating_sub(base_stat.crit_chance),
        damage_percent,
        true,
        1,
    );

    if candidates.is_empty() {
        return;
    }

    let Some(roll) = random_index(
        splitmix64(
            ctx.seed()
                ^ ((caster_id as u64) << 32)
                ^ ((target_id as u64) << 12)
                ^ ctx.tick() as u64,
        ),
        candidates.len(),
    ) else {
        return;
    };
    let Some((ad_damage, ap_damage)) = candidates.get(roll).copied() else {
        return;
    };
    if ad_damage == 0 && ap_damage == 0 {
        return;
    }

    let defender_types = effective_defender_types(ctx, target_id, PokemonType::Ghost);
    deal_or_volt_absorb_pokemon_damage(
        ctx,
        caster_id,
        target_id,
        ad_damage,
        ap_damage,
        AttackType::Skill,
        PokemonType::Ghost,
        attacker_types,
        defender_types,
    );
}

fn push_poltergeist_candidate(
    candidates: &mut Vec<(usize, usize)>,
    surplus: usize,
    damage_percent: usize,
    physical: bool,
    divisor: usize,
) {
    let damage = surplus
        .saturating_mul(damage_percent)
        .saturating_div(100usize.saturating_mul(divisor.max(1)));
    if damage == 0 {
        return;
    }
    if physical {
        candidates.push((damage, 0));
    } else {
        candidates.push((0, damage));
    }
}

fn apply_mega_launcher_damage(
    ctx: &GameCtx,
    caster_id: usize,
    target_id: usize,
    hit_index: usize,
    ad_damage: usize,
    ap_damage: usize,
    generic_crit_chance: usize,
) -> (usize, usize) {
    if crate::pokemon_status::has_shell_armor(ctx, target_id) {
        return (ad_damage, ap_damage);
    }

    let crit_percent = crate::pokemon_status::note_mega_launcher_hit(ctx, caster_id, target_id);
    let crit_percent = crit_percent.saturating_add(generic_crit_chance);
    if !mega_launcher_crits(
        ctx.seed(),
        caster_id,
        target_id,
        ctx.tick(),
        hit_index,
        crit_percent,
    ) {
        return (ad_damage, ap_damage);
    }

    let crit_damage_percent = crate::pokemon_status::adjust_incoming_critical_damage_percent(
        ctx,
        target_id,
        200 + crit_percent.saturating_sub(100),
    );
    (
        ad_damage.saturating_mul(crit_damage_percent) / 100,
        ap_damage.saturating_mul(crit_damage_percent) / 100,
    )
}

fn apply_basic_attack_crit(
    ctx: &GameCtx,
    champion_id: &str,
    action: PokemonMove,
    effect: PokemonMoveEffect,
    crit_chance: usize,
    caster_id: usize,
    target_id: usize,
    hit_index: usize,
    ad_damage: usize,
    ap_damage: usize,
) -> (usize, usize) {
    let can_crit = is_basic_action(action)
        || (champion_id == "pokemon_moba_kleavor"
            && matches!(effect, PokemonMoveEffect::MultiHitDamage { .. }))
        || (champion_id == "pokemon_moba_cloyster"
            && matches!(effect, PokemonMoveEffect::CloysterIcicleCrash { .. }))
        || leek_crit_eligible(ctx, caster_id, champion_id, action);
    if crit_chance == 0
        || !can_crit
        || crate::pokemon_status::has_shell_armor(ctx, target_id)
        || !basic_attack_crits(
            ctx.seed(),
            caster_id,
            target_id,
            ctx.tick(),
            hit_index,
            crit_chance,
        )
    {
        return (ad_damage, ap_damage);
    }

    let crit_damage_percent = crate::pokemon_status::adjust_incoming_critical_damage_percent(
        ctx,
        target_id,
        crit_damage_percent(caster_id, champion_id, crit_chance),
    );
    (
        ad_damage.saturating_mul(crit_damage_percent) / 100,
        ap_damage.saturating_mul(crit_damage_percent) / 100,
    )
}

fn crit_damage_percent(caster_id: usize, champion_id: &str, crit_chance: usize) -> usize {
    let base_percent = if champion_id == "pokemon_moba_inteleon"
        || crate::pokemon_status::receiver_has_copied(caster_id, "pokemon_moba_inteleon")
    {
        250
    } else {
        200
    };
    let surplus = crit_chance.saturating_sub(100);
    let surplus = if champion_id == "pokemon_moba_sirfetchd"
        || crate::pokemon_status::receiver_has_copied(caster_id, "pokemon_moba_sirfetchd")
    {
        surplus / 2
    } else {
        surplus
    };
    base_percent + surplus
}

fn bonus_ad_amount(champion_id: &str, level: usize, current_attack: usize) -> usize {
    champion_base_stat_for_level(champion_id, level)
        .map(|base| current_attack.saturating_sub(base.attack))
        .unwrap_or(0)
}

fn kingdra_dragon_dance_extra_damage(level: usize) -> (usize, usize) {
    let base = if level >= 10 {
        76
    } else if level >= 7 {
        60
    } else if level >= 4 {
        44
    } else {
        28
    };
    (base, 16)
}

fn kingdra_dragon_pulse_base_damage(level: usize) -> usize {
    if level >= 10 {
        400
    } else if level >= 5 {
        280
    } else {
        160
    }
}

fn cloyster_level_value(
    level: usize,
    value_1: usize,
    value_2: usize,
    value_3: usize,
    value_4: usize,
) -> usize {
    if level >= 10 {
        value_4
    } else if level >= 7 {
        value_3
    } else if level >= 4 {
        value_2
    } else {
        value_1
    }
}

fn cloyster_clamp_threshold_percent(level: usize) -> usize {
    cloyster_level_value(level, 20, 25, 30, 35)
}

fn cloyster_clamp_missing_hp_bonus(ctx: &GameCtx, target_id: usize, level: usize) -> usize {
    let Some(target) = ctx.get_entity(target_id) else {
        return 0;
    };
    let hp = target.hp();
    let is_capped_target = !target.is_champion();
    drop(target);
    if hp.max == 0
        || hp.current.saturating_mul(100)
            > hp.max
                .saturating_mul(cloyster_clamp_threshold_percent(level))
    {
        return 0;
    }
    let damage = hp.max.saturating_sub(hp.current).saturating_mul(5) / 100;
    if is_capped_target {
        damage.min(200)
    } else {
        damage
    }
}

fn kleavor_sharpness_crit_bonus(hit_count: Option<usize>) -> usize {
    hit_count
        .map(|hits| hits.saturating_sub(1).saturating_mul(5).min(50))
        .unwrap_or(0)
}

fn leek_crit_bonus(
    ctx: &GameCtx,
    caster_id: usize,
    champion_id: &str,
    action: PokemonMove,
) -> usize {
    if leek_crit_eligible(ctx, caster_id, champion_id, action) {
        50
    } else {
        0
    }
}

fn leek_crit_eligible(
    ctx: &GameCtx,
    caster_id: usize,
    champion_id: &str,
    action: PokemonMove,
) -> bool {
    if champion_id == "pokemon_moba_sirfetchd" {
        matches!(
            action.slot,
            ActionSlot::Attack | ActionSlot::Skill | ActionSlot::Ult
        )
    } else if crate::pokemon_status::receiver_has_copied(caster_id, "pokemon_moba_sirfetchd") {
        is_basic_action(action)
    } else {
        let _ = ctx;
        false
    }
}

fn is_punch_action(champion_id: &str, action: PokemonMove) -> bool {
    let name = move_display_name(champion_id, action.name_key).to_ascii_lowercase();
    name.contains("punch")
}

fn is_kick_action(champion_id: &str, action: PokemonMove) -> bool {
    let name = move_display_name(champion_id, action.name_key).to_ascii_lowercase();
    name.contains("kick") || name.contains("low sweep") || name.contains("axe kick")
}

fn basic_attack_crits(
    seed: u64,
    caster_id: usize,
    target_id: usize,
    tick: usize,
    hit_index: usize,
    crit_chance: usize,
) -> bool {
    if crit_chance >= 100 {
        return true;
    }
    let roll = splitmix64(
        seed ^ ((caster_id as u64) << 44)
            ^ ((target_id as u64) << 20)
            ^ (tick as u64)
            ^ ((hit_index as u64) << 8)
            ^ 0xc217_u64,
    ) % 100;
    roll < crit_chance as u64
}

fn mega_launcher_crits(
    seed: u64,
    caster_id: usize,
    target_id: usize,
    tick: usize,
    hit_index: usize,
    crit_percent: usize,
) -> bool {
    if crit_percent >= 100 {
        return true;
    }
    let roll = splitmix64(
        seed ^ ((caster_id as u64) << 48)
            ^ ((target_id as u64) << 24)
            ^ (tick as u64)
            ^ hit_index as u64,
    ) % 100;
    roll < crit_percent as u64
}

fn chance_percent(
    seed: u64,
    caster_id: usize,
    target_id: usize,
    tick: usize,
    percent: usize,
) -> bool {
    if percent >= 100 {
        return true;
    }
    let roll = splitmix64(
        seed ^ ((caster_id as u64) << 40)
            ^ ((target_id as u64) << 16)
            ^ (tick as u64)
            ^ 0xa11ce_u64,
    ) % 100;
    roll < percent as u64
}

fn splitmix64(mut value: u64) -> u64 {
    value = value.wrapping_add(0x9e3779b97f4a7c15);
    value = (value ^ (value >> 30)).wrapping_mul(0xbf58476d1ce4e5b9);
    value = (value ^ (value >> 27)).wrapping_mul(0x94d049bb133111eb);
    value ^ (value >> 31)
}

fn random_index(seed: u64, len: usize) -> Option<usize> {
    if len == 0 {
        None
    } else {
        Some((seed as usize) % len)
    }
}

