impl PokemonType {
    pub const fn asset_tag(self) -> &'static str {
        match self {
            PokemonType::Normal => "normal",
            PokemonType::Fire => "fire",
            PokemonType::Water => "water",
            PokemonType::Electric => "electric",
            PokemonType::Grass => "grass",
            PokemonType::Ice => "ice",
            PokemonType::Fighting => "fighting",
            PokemonType::Poison => "poison",
            PokemonType::Ground => "ground",
            PokemonType::Flying => "flying",
            PokemonType::Psychic => "psychic",
            PokemonType::Bug => "bug",
            PokemonType::Rock => "rock",
            PokemonType::Ghost => "ghost",
            PokemonType::Dragon => "dragon",
            PokemonType::Dark => "dark",
            PokemonType::Steel => "steel",
            PokemonType::Fairy => "fairy",
            PokemonType::Bird => "bird",
        }
    }
}

pub const fn stat(
    attack: usize,
    magic_power: usize,
    hp: usize,
    defence: usize,
    magic_resistance: usize,
    move_speed: usize,
    hp_regen: usize,
) -> EntityStat {
    EntityStat {
        attack,
        magic_power,
        hp,
        defence,
        magic_resistance,
        move_speed,
        hp_regen,
        stack: 0,
        crit_chance: 0,
    }
}

#[cfg(test)]
mod guide_export_tests {
    use super::*;
    use crate::pokemon_positions::POKEMON_POSITIONS;
    use crate::pokemon_strategy::{strategy_for_champion_id, StrategyTrait};
    use crate::pokemon_types::{type_modifier_ratio, PokemonType};
    use std::fs;

    const GUIDE_EXPORT_PATH: &str =
        r"C:\Users\james\Documents\TFT Pokemon Mod\scratch\pokemon_guide_data.json";

    const TYPES: [PokemonType; 19] = [
        PokemonType::Normal,
        PokemonType::Fire,
        PokemonType::Water,
        PokemonType::Electric,
        PokemonType::Grass,
        PokemonType::Ice,
        PokemonType::Fighting,
        PokemonType::Poison,
        PokemonType::Ground,
        PokemonType::Flying,
        PokemonType::Psychic,
        PokemonType::Bug,
        PokemonType::Rock,
        PokemonType::Ghost,
        PokemonType::Dragon,
        PokemonType::Dark,
        PokemonType::Steel,
        PokemonType::Fairy,
        PokemonType::Bird,
    ];

    #[test]
    fn export_pokemon_guide_data() {
        let _ = fs::create_dir_all(r"C:\Users\james\Documents\TFT Pokemon Mod\scratch");
        fs::write(GUIDE_EXPORT_PATH, guide_json()).expect("write pokemon guide data");
        eprintln!("wrote {GUIDE_EXPORT_PATH}");
    }

    fn guide_json() -> String {
        format!(
            "{{\"champions\":[{}],\"type_chart\":[{}]}}",
            POKEMON_CHAMPIONS
                .iter()
                .map(|champion| champion_json(*champion))
                .collect::<Vec<_>>()
                .join(","),
            type_chart_json()
        )
    }

    fn champion_json(champion: PokemonChampion) -> String {
        let level_12 = champion_base_stat_for_level(champion.id, 12).unwrap_or(champion.stat);
        let positions = POKEMON_POSITIONS
            .iter()
            .find(|info| info.id == champion.id)
            .map(|info| info.label)
            .unwrap_or("Unlisted");
        let moves = moveset_summary_for_champion_id(champion.id).unwrap_or_default();

        format!(
            "{{\"id\":{},\"name\":{},\"short_id\":{},\"types\":[{}],\"category\":{},\"tags\":[{}],\"positions\":{},\"stats\":{{\"base\":{},\"growth\":{},\"level12\":{}}},\"moves\":[{}],\"matchups\":{},\"strategy\":{}}}",
            json_str(champion.id),
            json_str(champion.display_name),
            json_str(champion.short_id()),
            type_set_json(champion.types),
            json_str(&format!("{:?}", champion.category)),
            champion
                .tags
                .iter()
                .map(|tag| json_str(&format!("{tag:?}")))
                .collect::<Vec<_>>()
                .join(","),
            json_str(positions),
            stat_json(champion.stat),
            stat_json(champion.growth),
            stat_json(level_12),
            moves
                .iter()
                .map(move_json)
                .collect::<Vec<_>>()
                .join(","),
            champion_matchup_json(champion),
            champion_strategy_json(champion.id)
        )
    }

    fn move_json(move_info: &PokemonMoveSummary) -> String {
        format!(
            "{{\"id\":{},\"role\":{},\"name\":{},\"description\":{},\"cooldown\":{},\"icon_source\":{},\"icon_tag\":{}}}",
            json_str(move_info.id),
            json_str(move_info.role),
            json_str(&move_info.name),
            json_str(&move_info.description),
            move_info
                .cooldown
                .map(|cooldown| cooldown.to_string())
                .unwrap_or_else(|| "null".to_string()),
            json_str(move_info.icon_source),
            json_str(&move_info.icon_tag),
        )
    }

    fn champion_matchup_json(champion: PokemonChampion) -> String {
        let mut weak_to = Vec::new();
        let mut resists = Vec::new();
        for move_type in TYPES {
            let (num, den) = type_modifier_ratio(move_type, champion.types);
            if num > den {
                weak_to.push(type_name(move_type));
            } else if num < den {
                resists.push(type_name(move_type));
            }
        }

        format!(
            "{{\"weak_to\":[{}],\"resists\":[{}]}}",
            weak_to
                .iter()
                .map(|name| json_str(name))
                .collect::<Vec<_>>()
                .join(","),
            resists
                .iter()
                .map(|name| json_str(name))
                .collect::<Vec<_>>()
                .join(","),
        )
    }

    fn champion_strategy_json(champion_id: &str) -> String {
        let Some(strategy) = strategy_for_champion_id(champion_id) else {
            return "{\"traits\":[],\"threatens\":[],\"vulnerable_to\":[]}".to_string();
        };

        format!(
            "{{\"traits\":[{}],\"threatens\":[{}],\"vulnerable_to\":[{}]}}",
            strategy_traits_json(strategy.traits),
            strategy_traits_json(strategy.threatens),
            strategy_traits_json(strategy.vulnerable_to),
        )
    }

    fn strategy_traits_json(traits: &[StrategyTrait]) -> String {
        traits
            .iter()
            .map(|value| json_str(&format!("{value:?}")))
            .collect::<Vec<_>>()
            .join(",")
    }

    fn type_chart_json() -> String {
        let mut cells = Vec::new();
        for attack_type in TYPES {
            for defender_type in TYPES {
                let (num, den) = type_modifier_ratio(attack_type, TypeSet::single(defender_type));
                cells.push(format!(
                    "{{\"attack\":{},\"defense\":{},\"num\":{},\"den\":{}}}",
                    json_str(type_name(attack_type)),
                    json_str(type_name(defender_type)),
                    num,
                    den
                ));
            }
        }
        cells.join(",")
    }

    fn type_set_json(types: TypeSet) -> String {
        let mut values = vec![json_str(type_name(types.primary))];
        if let Some(secondary) = types.secondary {
            values.push(json_str(type_name(secondary)));
        }
        values.join(",")
    }

    fn stat_json(stat: EntityStat) -> String {
        format!(
            "{{\"attack\":{},\"magic_power\":{},\"hp\":{},\"defence\":{},\"magic_resistance\":{},\"move_speed\":{},\"hp_regen\":{},\"crit_chance\":{}}}",
            stat.attack,
            stat.magic_power,
            stat.hp,
            stat.defence,
            stat.magic_resistance,
            stat.move_speed,
            stat.hp_regen,
            stat.crit_chance,
        )
    }

    fn type_name(value: PokemonType) -> &'static str {
        match value {
            PokemonType::Normal => "Normal",
            PokemonType::Fire => "Fire",
            PokemonType::Water => "Water",
            PokemonType::Electric => "Electric",
            PokemonType::Grass => "Grass",
            PokemonType::Ice => "Ice",
            PokemonType::Fighting => "Fighting",
            PokemonType::Poison => "Poison",
            PokemonType::Ground => "Ground",
            PokemonType::Flying => "Flying",
            PokemonType::Psychic => "Psychic",
            PokemonType::Bug => "Bug",
            PokemonType::Rock => "Rock",
            PokemonType::Ghost => "Ghost",
            PokemonType::Dragon => "Dragon",
            PokemonType::Dark => "Dark",
            PokemonType::Steel => "Steel",
            PokemonType::Fairy => "Fairy",
            PokemonType::Bird => "Bird",
        }
    }

    fn json_str(value: &str) -> String {
        let mut output = String::from("\"");
        for ch in value.chars() {
            match ch {
                '"' => output.push_str("\\\""),
                '\\' => output.push_str("\\\\"),
                '\n' => output.push_str("\\n"),
                '\r' => output.push_str("\\r"),
                '\t' => output.push_str("\\t"),
                '\u{08}' => output.push_str("\\b"),
                '\u{0c}' => output.push_str("\\f"),
                ch if ch < ' ' => output.push_str(&format!("\\u{:04x}", ch as u32)),
                ch => output.push(ch),
            }
        }
        output.push('"');
        output
    }
}
